import { Flashcard } from './ib-flashcard-data';
export const ST_FLASHCARDS: Flashcard[] = [
// MARKET STRUCTURE (35)
{q:"What is the bid-ask spread?",a:"Difference between highest buy (bid) and lowest sell (ask). Compensates for inventory risk and adverse selection.",category:"Market Structure",difficulty:"Intermediate"},
{q:"Market order vs limit order?",a:"Market: immediate, pays spread. Limit: posts liquidity, may earn spread but faces fill uncertainty.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is adverse selection?",a:"Informed traders trade against you when your quote is stale. Key risk for market makers.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is VWAP?",a:"Volume-Weighted Average Price. Execution benchmark. Sum(price × volume) / total volume.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is a dark pool?",a:"Private exchange with no pre-trade transparency. Reduces market impact for large orders.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is market impact?",a:"Your trade moves the price. Larger orders in illiquid markets have more impact.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is slippage?",a:"Difference between expected and actual execution price. Due to market movement, impact, or delay.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is a market maker?",a:"Quotes bid and ask, provides liquidity. Earns spread but bears inventory and adverse selection risk.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is an order book?",a:"Electronic list of buy and sell orders at various prices. Shows market depth.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is price-time priority?",a:"Orders filled by best price first, then earliest arrival. Standard exchange matching.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is a block trade?",a:"Large transaction negotiated privately to minimize impact. Often via dealers or dark pools.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is implementation shortfall?",a:"Difference between paper return (decision price) and actual return after execution. Captures all costs.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is TWAP?",a:"Time-Weighted Average Price algorithm. Spreads orders evenly over time.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is liquidity?",a:"Ability to buy/sell without significantly moving price. Measured by spread, depth, volume.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is a crossing network?",a:"Matches buys and sells at a reference price (midpoint) without price discovery.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is a specialist vs DMM?",a:"Designated Market Maker: assigned to specific securities, obligated to quote and maintain orderly markets.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is high-frequency trading?",a:"Algorithmic trading at microsecond speeds. Earns from market making, arbitrage, and speed advantages.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is co-location?",a:"Placing trading servers physically near exchange matching engines. Reduces latency by microseconds.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is a circuit breaker?",a:"Trading halts triggered by large price moves. Prevents cascading sell-offs. Level 1/2/3 in US markets.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is Reg NMS?",a:"National Market System rules. Requires best price execution across exchanges. Order protection rule.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is payment for order flow?",a:"Broker routes retail orders to market makers who pay for the flow. Controversial: conflict of interest vs price improvement.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is the bid-ask bounce?",a:"Trades alternating between bid and ask create apparent volatility even without true price change.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is a fill rate?",a:"Percentage of limit orders that execute. Higher for aggressive (closer to market) orders.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is a market-on-close order?",a:"Executes at closing auction price. Important for benchmarking and index rebalancing.",category:"Market Structure",difficulty:"Intermediate"},
{q:"What is an iceberg order?",a:"Large order with only a small portion visible on the book. Rest hidden. Reduces market impact.",category:"Market Structure",difficulty:"Intermediate"},
// FIXED INCOME (40)
{q:"What is duration?",a:"Bond price sensitivity to rate changes. Longer duration = more sensitivity.",category:"Fixed Income",difficulty:"Advanced"},
{q:"What is modified duration?",a:"Approximate % price change for 1% rate change. Duration / (1 + yield).",category:"Fixed Income",difficulty:"Advanced"},
{q:"What is convexity?",a:"Second-order price sensitivity. Positive convexity: price rises more for rate falls than drops for rate rises.",category:"Fixed Income",difficulty:"Advanced"},
{q:"What is a yield curve?",a:"Yields across maturities. Normal = upward. Inverted = short > long, signals recession.",category:"Fixed Income",difficulty:"Advanced"},
{q:"What is credit spread?",a:"Yield premium over risk-free for default/liquidity risk. Widening = stress.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is repo?",a:"Short-term borrowing collateralized by securities. Fundamental to bond financing.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is carry?",a:"Income from holding position over time. Bond carry = coupon minus funding cost.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is roll-down?",a:"Price gain as bond ages and moves down a normal yield curve to lower yields.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is DV01?",a:"Dollar value of 1 basis point yield move. Key risk metric.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is a basis point?",a:"1/100th of 1%. 100 bps = 1%.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is yield to maturity?",a:"Total return if held to maturity assuming reinvestment. Bond's IRR.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"Current yield vs YTM?",a:"Current = coupon/price. YTM includes gain/loss and reinvestment. YTM more complete.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is a callable bond?",a:"Issuer can redeem early. Benefits issuer if rates fall. Buyer demands higher yield.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is a zero-coupon bond?",a:"No coupons. Sold at discount, matures at par. All return from appreciation.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"Treasury vs corporate bond?",a:"Treasury: US gov, risk-free benchmark. Corporate: credit risk, higher yield.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"Price and yield relationship?",a:"Inverse. Rates up → prices down. Rates down → prices up.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is a CDS?",a:"Credit Default Swap. Insurance against default. Buyer pays premium, seller pays on credit event.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"High yield vs investment grade?",a:"IG: BBB-/Baa3 and above. HY: below. Higher yield, higher default risk.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"Inverted yield curve signal?",a:"Short rates > long rates. Historically signals recession expectations.",category:"Fixed Income",difficulty:"Advanced"},
{q:"What is a steepener trade?",a:"Bet curve steepens (long rates rise vs short). Often uses futures or swaps.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is a flattener trade?",a:"Bet curve flattens. Short long-end, long short-end.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is negative convexity?",a:"Price appreciation slows as rates fall (callable bonds, MBS). Hurts holders.",category:"Fixed Income",difficulty:"Advanced"},
{q:"What is spread duration?",a:"Sensitivity to credit spread changes. Separate from rate duration.",category:"Fixed Income",difficulty:"Advanced"},
{q:"What is a TIP (TIPS)?",a:"Treasury Inflation-Protected Securities. Principal adjusts with CPI. Protects against inflation.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is a floating rate note?",a:"Coupon resets periodically (SOFR + spread). Low duration risk.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is a mortgage-backed security?",a:"Bond backed by pool of mortgages. Prepayment risk is unique feature.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is prepayment risk?",a:"Borrowers refinance when rates fall, returning principal early. Investor loses high-coupon cash flows.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is a swap?",a:"Exchange of cash flows. Interest rate swap: fixed for floating. Key for hedging and expressing rate views.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is the swap rate?",a:"Fixed rate in a swap. Benchmark for credit markets. Swap spread = swap rate minus Treasury.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is SOFR?",a:"Secured Overnight Financing Rate. Replaced LIBOR as benchmark for floating-rate instruments.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is a bond auction?",a:"Government issues new bonds. Primary dealers bid. Sets market clearing yield.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is a term premium?",a:"Extra yield for holding longer-maturity bonds. Compensates for duration risk and uncertainty.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is a real vs nominal yield?",a:"Nominal = stated yield. Real = nominal minus inflation. TIPS yield is a real yield.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is a basis trade?",a:"Trading difference between cash bond and futures. Arbitrage relationship.",category:"Fixed Income",difficulty:"Intermediate"},
{q:"What is an asset swap?",a:"Combining bond with swap to convert fixed coupon to floating. Isolates credit spread.",category:"Fixed Income",difficulty:"Intermediate"},
// OPTIONS (30)
{q:"What is delta?",a:"Option price sensitivity to underlying. Calls: 0 to 1. Puts: -1 to 0.",category:"Options",difficulty:"Intermediate"},
{q:"What is gamma?",a:"Rate of change of delta. Highest ATM near expiry. Measures convexity.",category:"Options",difficulty:"Intermediate"},
{q:"What is theta?",a:"Time decay. Options lose value as time passes. Short options benefit.",category:"Options",difficulty:"Intermediate"},
{q:"What is vega?",a:"Sensitivity to implied vol. Long options = long vega.",category:"Options",difficulty:"Intermediate"},
{q:"What is implied vol?",a:"Vol making model price = market price. Market's pricing language.",category:"Options",difficulty:"Intermediate"},
{q:"What is a straddle?",a:"Long call + long put, same strike. Profits from large moves. Buying vol.",category:"Options",difficulty:"Intermediate"},
{q:"What is a strangle?",a:"Long OTM call + OTM put. Cheaper than straddle, needs bigger move.",category:"Options",difficulty:"Intermediate"},
{q:"What is a butterfly?",a:"Buy low + high strike, sell 2 ATM. Profits if underlying stays near ATM.",category:"Options",difficulty:"Intermediate"},
{q:"What is a covered call?",a:"Long stock + short call. Earns premium, caps upside. Income strategy.",category:"Options",difficulty:"Intermediate"},
{q:"What is a protective put?",a:"Long stock + long put. Insurance against downside.",category:"Options",difficulty:"Intermediate"},
{q:"Put-call parity?",a:"C - P = S - Ke^(-rT). Core no-arbitrage identity.",category:"Options",difficulty:"Intermediate"},
{q:"What is a collar?",a:"Long stock + long OTM put + short OTM call. Limits both sides.",category:"Options",difficulty:"Intermediate"},
{q:"What is a calendar spread?",a:"Same strike, different expirations. Profits from time decay differential.",category:"Options",difficulty:"Intermediate"},
{q:"What is a risk reversal?",a:"Long OTM call + short OTM put (or vice versa). Directional using options.",category:"Options",difficulty:"Intermediate"},
{q:"What is gamma scalping?",a:"Delta-hedging long gamma position. Profit from realized > implied vol.",category:"Options",difficulty:"Intermediate"},
{q:"Intrinsic vs time value?",a:"Intrinsic = ITM amount. Time value = premium minus intrinsic. Decays to zero.",category:"Options",difficulty:"Intermediate"},
{q:"What is the vol surface?",a:"3D: implied vol across strikes and expirations. Shows skew and term structure.",category:"Options",difficulty:"Intermediate"},
{q:"What is skew?",a:"Implied vol difference across strikes. Downside puts typically higher vol.",category:"Options",difficulty:"Intermediate"},
{q:"What is term structure of vol?",a:"How implied vol varies across expirations. Can slope up, flat, or inverted.",category:"Options",difficulty:"Intermediate"},
{q:"What is a variance swap?",a:"Swap paying realized minus implied variance. Pure vol bet, no delta.",category:"Options",difficulty:"Intermediate"},
{q:"What is a vol-of-vol?",a:"Volatility of implied volatility itself. Matters for exotic options pricing.",category:"Options",difficulty:"Intermediate"},
{q:"What is a digital/binary option?",a:"Pays fixed amount if condition met (e.g., above strike), zero otherwise.",category:"Options",difficulty:"Intermediate"},
{q:"What is an iron condor?",a:"Short strangle + long further OTM strangle. Profits from low vol, limited risk.",category:"Options",difficulty:"Intermediate"},
{q:"What is a ratio spread?",a:"Unequal number of long and short options. Directional with skew exposure.",category:"Options",difficulty:"Intermediate"},
{q:"What is early exercise?",a:"American option exercised before expiry. Calls: rarely optimal (non-dividend). Puts: may be optimal.",category:"Options",difficulty:"Intermediate"},
{q:"What is pin risk?",a:"Risk near expiry when underlying is close to strike. Uncertainty about exercise.",category:"Options",difficulty:"Intermediate"},
{q:"What is a VIX future?",a:"Futures on expected 30-day S&P vol. Usually in contango (futures > spot).",category:"Options",difficulty:"Intermediate"},
{q:"What is contango vs backwardation in vol?",a:"Contango: future vol > spot vol (normal). Backwardation: spot > future (during stress).",category:"Options",difficulty:"Intermediate"},
// TRADE IDEAS & MACRO (25)
{q:"Pitch me a trade.",a:"Thesis → instrument → entry/target/stop → risk management → catalyst. Be specific, acknowledge risks.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"$1M to invest - what would you do?",a:"Macro view, asset allocation, specific ideas with risk/reward. Show sizing and what's priced in.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"What is a carry trade?",a:"Borrow low-yield, invest high-yield. Profitable if stable. Exposed to reversals.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"What is a pairs trade?",a:"Long one, short correlated other. Bet on relative performance. Market-neutral.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"What is a convergence trade?",a:"Bet two prices will converge. Common in arb strategies.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"What macro theme are you following?",a:"Pick something current. Show depth - transmission mechanism and positioning implications.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"Central bank decisions affect markets how?",a:"Rate changes affect discount rates, credit, currency, risk appetite. Guidance shapes expectations.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"Risk-on vs risk-off?",a:"Risk-on: equities up, spreads tight, vol low. Risk-off: flight to quality, vol spike, spreads widen.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"What is a short squeeze?",a:"Sharp rise forces shorts to cover, creating more buying pressure.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"What drives FX rates?",a:"Rate differentials, trade balances, capital flows, inflation, policy, risk sentiment.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"What is a tail risk hedge?",a:"Position protecting against extremes - deep OTM puts, VIX calls. Insurance with negative carry.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"What is momentum?",a:"Trend continuation: recent winners keep winning. Works across assets but can reverse sharply.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"What is mean reversion?",a:"Prices tend toward long-run average. Basis for relative value strategies.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"What is the VIX?",a:"S&P 500 implied vol index. 'Fear gauge.' Spikes during stress.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"What is a relative value trade?",a:"Exploiting mispricing between related securities rather than taking directional risk.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"What is a curve trade?",a:"Positioning on yield curve shape: steepener, flattener, butterfly.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"What is a cross-asset trade?",a:"Trading relationship between asset classes: equity vs credit, rates vs FX.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"What is an event-driven trade?",a:"Positioning around earnings, central bank meetings, elections, regulatory decisions.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"What is a regime change?",a:"Shift in market dynamics: inflation to deflation, risk-on to risk-off, growth to recession.",category:"Trade Ideas",difficulty:"Intermediate"},
{q:"What is positioning data?",a:"Shows how traders are positioned (COT reports, fund flows). Extreme positioning can signal reversals.",category:"Trade Ideas",difficulty:"Intermediate"},
// BEHAVIORAL (20)
{q:"Why sales and trading?",a:"Fast-paced, markets-focused, immediate feedback, analytical + intuition + risk management.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Sales vs trading difference?",a:"Sales: client relationships, market color. Trading: risk-taking, position management.",category:"Behavioral",difficulty:"Intermediate"},
{q:"How do you handle a losing trade?",a:"Re-evaluate thesis. If broken, cut. If thesis holds and risk manageable, may hold. Never denial.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Tell me about a trade you'd put on.",a:"Specific, well-reasoned. Know instrument, risk/reward, what goes wrong.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What markets do you follow?",a:"Be specific: equities, rates, credit, FX, commodities. Know recent moves and drivers.",category:"Behavioral",difficulty:"Intermediate"},
{q:"How do you stay informed?",a:"Bloomberg, WSJ, FT, research, earnings calls, central bank comms. Show genuine engagement.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Tell me about a calculated risk.",a:"Risk assessment, decision process, outcome, learning. Disciplined risk-taking.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What's your edge?",a:"Be honest. Speed, pattern recognition, discipline, specific knowledge. Don't overclaim.",category:"Behavioral",difficulty:"Intermediate"},
{q:"How do you size a position?",a:"Conviction, vol, liquidity, correlation, max loss tolerance. Risk-based sizing.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Tell me about yourself.",a:"Markets interest → experience → quantitative/analytical skills → why S&T.",category:"Behavioral",difficulty:"Intermediate"},
{q:"How do you manage risk?",a:"Position limits, stop-losses, diversification, correlation awareness, scenario analysis.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What is the most important quality for a trader?",a:"Discipline. Cutting losses, sticking to process, not chasing, managing emotions.",category:"Behavioral",difficulty:"Intermediate"},
{q:"Tell me about a time you were wrong.",a:"What was the thesis, what happened, how you managed it, what you learned.",category:"Behavioral",difficulty:"Intermediate"},
{q:"What would you do on your first day?",a:"Learn the desk, understand positions, observe, ask questions, build relationships.",category:"Behavioral",difficulty:"Intermediate"},
{q:"How do you handle stress?",a:"Stay calm, focus on process not outcome, take breaks, maintain perspective.",category:"Behavioral",difficulty:"Intermediate"},
// ── ADVANCED S&T INTERVIEW FLASHCARDS (150) — uploaded 2026-05-18 ──
{q:"CPI prints 50bps above consensus. Walk me through how you'd position the curve in the first hour.",a:"First reaction is the front end sells off hardest - 2s repricing hawkish Fed expectations and pushing the curve flatter or even inverted further. I'd want to be short the front end, paying 2y SOFR swaps or shorting the 2y note. The long end moves less because terminal rate expectations matter more than path, and real money will buy duration once the move overshoots. Breakevens widen as inflation expectations re-anchor, so I'd consider buying TIPS breakevens. The trap is fading the move too early - hot CPI prints usually have follow-through over several sessions as systematic strategies and dealer hedging extend the move.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Fed signals a dovish pivot but inflation is sticky at 3.5%. What does that do to 2s10s and breakevens?",a:"The 2y rallies on cut expectations while the long end sells off because the market prices a Fed that's letting inflation run hotter than mandate - that's a bear steepener. Breakevens widen sharply because the credibility hit feeds inflation expectations higher. The trade is curve steepeners paired with long breakevens or short TIPS. The classic policy mistake setup - cutting before inflation is dead - is exactly what bond vigilantes punish at the long end. Gold typically catches a bid in this regime because real yields fall as nominals stay anchored but expected inflation rises.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through the transmission of a 25bp Fed cut through the dollar, EM FX, and US tech equity multiples.",a:"The cut typically weakens the dollar at the margin because rate differentials narrow versus other developed currencies, particularly if the ECB or BOJ aren't expected to follow. A weaker dollar is a tailwind for EM FX, which rallies on the unwind of dollar funding pressure - high-carry EM (MXN, BRL, ZAR) tends to outperform low-carry EM. US long-duration equities benefit because the discount rate falls on future cash flows, so tech multiples expand. The full transmission takes weeks to months, but FX moves in seconds, equity multiples in days, and credit spreads progressively as financing costs ease. The setup reverses violently if the cut is interpreted as panic rather than calibration.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Real yields rise 30bps and gold rallies. How do you reconcile that?",a:"Real yields rising should be a headwind for gold under the textbook model - non-yielding asset gets less attractive as alternatives yield more. The fact that gold rallies anyway suggests something is driving demand beyond the real-rate channel. Most likely candidates are central bank buying (China, India, EM reserves diversification away from USD), geopolitical risk premium, or a credibility shock to the dollar reserve currency status. The relationship between gold and real yields has structurally broken down over the last few years as central bank flows have dominated marginal pricing. The trade implication is that gold has decoupled from rates and is responding to different drivers - sizing should reflect that.",category:"Fixed Income",difficulty:"Advanced"},
{q:"If breakevens widen 40bps while nominal yields fall 20bps, what's the implied move in real yields and how does that affect risk assets?",a:"Real yields are nominal minus breakevens, so real yields fall by 60bps - that's a major dovish impulse on top of falling nominal rates. Falling real yields are rocket fuel for risk assets: long-duration equities re-rate higher, gold rallies, credit spreads tighten, and EM benefits. The dollar typically weakens because real rate differentials narrow versus the rest of the world. The combination signals the market is pricing the Fed losing the inflation fight - accommodative enough on nominals but inflation expectations are unanchored. The trade is long anything that benefits from negative real rates: gold, BTC, long-duration equities, EM FX.",category:"Fixed Income",difficulty:"Advanced"},
{q:"ECB cuts before the Fed. What trade does that set up in EUR/USD and Bunds vs. Treasuries?",a:"ECB cutting first widens the rate differential in favor of the dollar, so EUR/USD weakens - short EUR/USD is the obvious expression. Bunds outperform Treasuries because German front-end rallies on cuts while US rates stay anchored, so paying Treasuries vs. receiving Bunds works. The risk to the trade is positioning - if EUR/USD short is crowded, you can get squeezed on any ECB hawkish surprise or dovish Fed signal. The more durable expression is steepener in Germany paired with flattener in the US, or buying European banks vs. US banks since US banks benefit from steeper curves while European banks benefit from ECB cuts not pinning the front end at zero anymore.",category:"Fixed Income",difficulty:"Advanced"},
{q:"The yield curve has been inverted for 18 months. Are you positioning for recession or unwind of inversion?",a:"Recession signals from inversion have a 12-24 month lag historically, so 18 months in is roughly the median time-to-recession window. But the inversion itself has been driven by a unique fiscal and post-pandemic backdrop - strong nominal GDP, large deficits funding term premium compression. The unwind usually comes through the front end rallying (recession signal) or the back end selling (term premium normalization). I'd lean toward the unwind being driven by front-end rallying - bear steepener trades feel late while bull steepeners feel right if growth is genuinely rolling over. Sizing matters more than direction here because timing has been a graveyard for short-rates traders.",category:"Fixed Income",difficulty:"Advanced"},
{q:"If you're a Treasury PM and the 30-year auction tails 4bps, walk me through what you do.",a:"A 4bp tail is meaningful - that's the auction stop yield higher than the when-issued indication just before, meaning real money demand was weaker than expected. The immediate reaction is the back end sells off and primary dealers end up holding more inventory than they wanted, which they need to distribute. If I'm long duration, I'm getting hit on the print, and I have to decide whether the weak auction is a one-off positioning issue or the start of a structural shift in foreign demand for Treasuries. A flatten trade (receive 5s, pay 30s) is the cleanest expression of further long-end weakness without taking outright duration risk. Watch the next few auctions to confirm whether the demand drop is structural.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through how QT actually drains liquidity from markets and where you'd watch for stress first.",a:"QT works by the Fed letting Treasuries and MBS roll off the balance sheet without reinvestment, which forces private sector participants to absorb the new issuance - that's reserves draining out of the banking system. Stress typically shows up first in repo markets, where short-term funding rates spike when reserves get tight, like September 2019. Money market funds and bank reserves are the canary. The other place is foreign demand for Treasuries - if dollar liquidity is tight globally, foreign central banks can't or won't buy as much. Watch the SOFR-IOR spread, the cross-currency basis, and term repo rates as early indicators.",category:"Fixed Income",difficulty:"Advanced"},
{q:"China devalues the yuan 3% overnight. Walk me through the cross-asset reaction in 24 hours.",a:"Risk-off across the board on the open - equities lower (especially EM, materials, semis exposed to China), commodities under pressure (copper, iron ore selling off hard), and Asian FX selling off in sympathy. The dollar rallies on flight to quality and Treasuries catch a bid. AUD typically gets hit because Australia is the high-beta China play through commodity exports. By Asian close, you'd see emerging market central bank intervention attempting to defend their currencies. By US open the next day, the focus shifts to whether other Asian central banks follow with their own devaluations - that's the second-wave risk. The 2015 yuan devaluation is the canonical playbook, with global equities down 10% over a few weeks.",category:"Fixed Income",difficulty:"Advanced"},
{q:"The Fed cuts 50bps when consensus expected 25. Would you buy 2-year or 30-year, and why?",a:"The 2-year rallies more on the surprise because the path of policy is what's being repriced - terminal rate expectations get lowered. But the 50bp cut also raises questions about why the Fed is moving faster than expected, which could signal recession or financial stress. If the cut is panic-driven, the long end might not rally as much because inflation expectations remain a concern. The cleanest expression is the 2-year if you trust the Fed's view, the 5-year if you want a duration play without taking long-end risk, and a steepener if you think the Fed is making a policy mistake. Sizing for a 50bp surprise should reflect that gamma - the move can extend further if other central banks follow.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Term premium goes from -50bps to +50bps over 6 months. What's driving it and what's the trade?",a:"A 100bp move in term premium is enormous and usually reflects a structural shift in demand for long bonds. Drivers could include: foreign demand decline (Japan, China reducing Treasury holdings), increased Treasury issuance to fund deficits, central bank QT pulling private buyers in, or a re-pricing of long-run inflation uncertainty. The trade depends on which driver dominates. If it's issuance-driven, you fade the move once auctions stabilize. If it's a credibility shock, you stay short the long end. Short 30y Treasuries vs. long 5y is the cleanest curve-steepener trade, or pay long-dated US rates vs. receive German Bunds if it's a US-specific issue.",category:"Fixed Income",difficulty:"Advanced"},
{q:"NFP prints -200K negative surprise but ISM Services is at 58. How do you read that, and what's the trade?",a:"Conflicting signals - NFP is a lagging indicator, ISM Services is more forward-looking and 58 is solidly expansionary. The market typically reacts to NFP first because it's the headline number, but the trade often fades within hours once people parse the data. I'd be careful about a knee-jerk rates rally; the front end might initially rally on cut expectations but reverse as the ISM data is digested. The right positioning is probably to fade the rates rally - pay rates on strength. If you have a strong macro view, the divergence is actually consistent with a soft landing scenario where labor cools but services demand holds, which is bullish risk assets and bearish duration.",category:"Fixed Income",difficulty:"Advanced"},
{q:"If oil rises $30 in a quarter, walk me through the rates and FX implications for Japan, India, and the US.",a:"Japan is a net oil importer with a weak currency - the yen weakens further as the terms-of-trade deteriorate, and BOJ faces pressure between currency stability and supporting the economy. India is also an oil importer with similar mechanics; INR weakens, current account widens, and the RBI may have to hike rates to defend the currency. The US is roughly oil-balanced after shale, but rising oil pushes headline inflation higher, which the Fed treats as transient unless wages respond. The trades are short JPY, short INR, long USD vs. these crosses, and watch for breakeven inflation widening in the US that pulls real yields lower.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through how you'd construct a trade expressing stagflation risk.",a:"Stagflation is rising inflation with weakening growth - the worst combination for traditional 60/40. The trade is long commodities (oil, gold, copper) for the inflation hedge, short long-duration equities (high-multiple tech) because rates rise while earnings fall, and long inflation breakevens or TIPS over nominals. In FX, short currencies of net commodity importers vs. exporters - long BRL, MXN, AUD vs. EUR, JPY, KRW. The hardest part is timing - stagflation expectations build slowly and unwind violently when growth recovers or inflation breaks. Size it like a tail hedge: small, asymmetric, and willing to bleed carry for the convexity.",category:"Fixed Income",difficulty:"Advanced"},
{q:"The BOJ ends YCC abruptly. What unwinds in global rates and FX?",a:"Japanese 10y yields rip higher (potentially 50-100bps), which pulls all developed market yields higher as Japanese investors stop reaching for yield abroad and start repatriating capital. USD/JPY drops sharply as the yen rallies on rate differential narrowing - could be a 5-10% move on a surprise. Treasury yields rise on the demand shock from Japanese real money potentially selling. The carry trade unwinds - anyone short JPY to fund long EM or risk asset positions gets squeezed. The August 2024 mini-episode is the playbook. The trades are short USD/JPY, long volatility (FX and rates), and short long-end global duration.",category:"Fixed Income",difficulty:"Advanced"},
{q:"A US recession hits but the Fed can't cut aggressively because of inflation. How do you position?",a:"Classic stagflation setup. Equities have to derate on falling earnings, but the rates rally is muted because the Fed is constrained - so the typical risk-off rates rally that cushions a recession doesn't fully materialize. Credit spreads widen meaningfully because corporate financing costs stay elevated through the recession. Trades: short cyclical equities (semis, industrials, consumer discretionary), long defensive (utilities, staples), short HY credit vs. IG, long gold, and a flattener trade in the front end. The 1970s playbook applies more than 2008-2020, which is unfamiliar territory for most traders.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through how a sovereign debt crisis in Italy would transmit to US Treasuries.",a:"Italian BTPs widen sharply versus Bunds - the BTP-Bund spread is the gauge of European sovereign stress. Initially, US Treasuries catch a flight-to-quality bid, so yields fall. But if the crisis escalates, foreign demand for Treasuries could weaken as European investors face their own liquidity demands and repatriate capital. The dollar typically rallies on European stress, putting pressure on EM. The 2011-2012 European debt crisis showed both phases: initial Treasury rally on flight-to-quality, then concern about US fiscal trajectory when the crisis spilled into broader risk-off. ECB response matters enormously - whatever-it-takes type intervention compresses spreads and reverses the trade.",category:"Fixed Income",difficulty:"Advanced"},
{q:"If 3-month T-bills yield more than 10-year Treasuries, what's the market actually saying about the path of rates?",a:"The market is pricing the Fed to cut rates over the next 10 years on average - short-rates expected to be lower than current. The 3m1y rate (one-year-forward 3-month rate) implied from the curve is below current 3m yields, which is the literal expression of expected cuts. Inversion has historically preceded recessions by 12-24 months, partly because it reflects monetary policy too tight relative to nominal GDP. The other interpretation is that term premium has been pushed to zero or negative by structural demand for duration, in which case the signal is muted. Either way, the curve is telling you the Fed is restrictive - and either growth slows enough to force cuts, or the curve eventually un-inverts through a back-end sell-off.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through the difference between a level shift, twist, and butterfly move in the curve.",a:"Level shift is a parallel move where all yields move in the same direction by similar amounts - driven by monetary policy expectations and inflation. Twist is when the front and back end move in opposite directions - bull steepener (front rallies, back unchanged or sells off) or bear flattener (front sells off, back unchanged or rallies). Butterfly is the belly (5y or 7y) moving differently from the wings (2y and 30y) - often a value or supply-driven move. Each carries different P&L implications for traders running different exposures. PCA analysis of curve moves shows that level explains roughly 80% of variance, slope another 15%, and curvature the rest - most P&L for outright traders comes from level, while RV traders care about twist and butterfly.",category:"Fixed Income",difficulty:"Advanced"},
{q:"If the cross-currency basis on EUR/USD blows out by 50bps, what does that tell you?",a:"Cross-currency basis is the cost of swapping one currency for another in the funding market - a wider negative basis means dollar funding is more expensive for European entities. A 50bp blowout signals dollar liquidity stress globally, often during risk-off or quarter-end balance sheet pressure. It usually shows up at year-end when banks pull balance sheet, in March 2020 during COVID stress, or during episodes of European banking concerns. The Fed's swap lines exist specifically to relieve this stress. Watch the basis as a real-time liquidity indicator; trade-wise, a blowout often precedes broader market stress and is a signal to derisk.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through a flattener vs. steepener trade and when you'd use each.",a:"Flattener: receive long end, pay short end - you benefit if the curve flattens (long-end rallies relative to short or short-end sells off relative to long). Used when you expect Fed hiking cycle to continue and bring front-end yields up, or when growth is slowing and long-end yields will fall. Steepener: pay long end, receive short end - you benefit if curve steepens. Used after a recession when Fed cuts the front while inflation or supply concerns hold up the long end, or when term premium is rebuilding. Bull steepeners (front rallies more than back) signal Fed cuts; bear steepeners (back sells off) signal supply or inflation concerns. The carry on each trade matters - flatteners typically have negative carry while steepeners have positive carry in normal curves.",category:"Fixed Income",difficulty:"Advanced"},
{q:"The Fed releases a hawkish dot plot but the stock market rallies. What's going on?",a:"Several explanations. First, the market may have already priced a more hawkish outcome than the dots suggest - relief rally on less hawkish than feared. Second, the dots reflect Committee views but the market trusts the market over the Committee, especially when growth is strong. Third, the rally might be flow-driven (gamma unclench, positioning unwind) and the underlying market reaction is more subdued than the price suggests. Fourth, the rally could be a head-fake before a follow-through sell-off. The desk wants to look at breadth, factor exposure, and where the buying is concentrated. If it's all in mega-cap tech with breadth weak, it's not a healthy rally.",category:"Fixed Income",difficulty:"Advanced"},
{q:"If wages re-accelerate to 5% YoY while unemployment ticks up to 4.5%, how do you trade that?",a:"Stagflation-lite setup - wages accelerating means inflation is sticky on the services side, while unemployment rising signals labor market softening. The Fed is in a tough spot: they want to cut on the labor weakness but can't because wages are still hot. Trades: bear flattener in the curve as the front-end stays high while the back end struggles; short long-duration equities; long defensive equities with pricing power (consumer staples, utilities); long short-dated breakevens. The market is pricing the wrong reaction function if it expects aggressive cuts. The 1970s parallel is useful - wage-price spirals were the killer of monetary policy credibility, and dot-plot guidance matters less than realized data.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through how an emerging market sovereign default ripples through DM credit and rates.",a:"Initial reaction is sharp risk-off - DM credit spreads widen, equities sell off, Treasuries and Bunds rally on flight to quality. The dollar rallies as global investors reduce risk and pull capital back to DM. Second-order effects depend on contagion: which other EM sovereigns are exposed, which banks have direct lending exposure, which credit funds get hit by redemptions. The Russia 1998 default cascaded through LTCM into G7 markets; Argentina 2001 was contained because it was telegraphed. The trades are widening IG-HY ratios, short EM FX (especially countries with similar fiscal profiles), and watching for forced selling in EM-focused credit funds that could spread to broader risk assets.",category:"Fixed Income",difficulty:"Advanced"},
{q:"SPX implied vol drops to 11. What does that signal and what's the asymmetric trade?",a:"VIX at 11 is bottom-decile historically - vol-of-vol is compressed, complacency is high, and the market is pricing very little event risk. The asymmetric trade is long volatility - buy ATM straddles or VIX call spreads as cheap convexity. The carry is bad (you bleed theta) but the payoff is enormous if vol spikes. The risk of the trade is that low vol can persist for months or years if conditions remain benign - 2017 was 12 months of sub-15 VIX. Sizing matters: this is a tail-risk hedge, not a core position. Pair it with selling longer-dated vol (term structure trade) to reduce carry, or wait for a catalyst window to put on the spike trade.",category:"Options",difficulty:"Advanced"},
{q:"Walk me through how dealer gamma positioning affects intraday SPX moves.",a:"When dealers are long gamma (typically the case in low-vol regimes with heavy call selling), they buy SPX as it falls and sell as it rises - that's mean-reverting flow that suppresses realized vol. When dealers are short gamma (often near major options expirations or after large index put buying), they buy as SPX rallies and sell as it falls - that's momentum flow that amplifies moves. The gamma flip level is the SPX price where dealer positioning shifts from long to short gamma. Around 0DTE expiration, dealers can be either side depending on positioning. Sites like SpotGamma try to estimate this in real time. Knowing dealer positioning helps explain why SPX can range for days then break violently in one direction.",category:"Options",difficulty:"Advanced"},
{q:"If put skew steepens sharply with no catalyst, what's likely going on?",a:"Put skew steepening means downside puts are getting bid more aggressively than ATM or upside calls - institutional money is hedging tail risk. Even without an obvious catalyst, this often shows up before market tops or during periods of complacent spot prices but rising under-the-surface concern. Could be flow-driven (one large hedger), positioning-driven (mass rebalancing into hedges), or anticipation-driven (event risk over coming weeks). The trade is often to lean against extreme skew once it overshoots - selling steep put skew tends to revert. But during genuine stress, skew can stay extreme for months. The diagnostic is whether realized vol is following implied higher or just skew steepening.",category:"Options",difficulty:"Advanced"},
{q:"A meme stock has 50% short interest and rallies 200% in a week. Walk me through what a market maker is doing.",a:"Hell, basically. Market makers are short calls (sold to retail), which means they have to delta hedge by buying stock as it rallies - that's a positive gamma feedback loop that drives the price higher (gamma squeeze). Short interest sitting at 50% means short sellers face mounting margin calls, and forced covering adds buying pressure on top of dealer hedging. Borrow rates spike from a few bps to tens of percent, making maintaining the short prohibitively expensive. Market makers widen bid-ask, may pull liquidity, and try to lay off risk in correlated names or index options. The unwind is brutal in both directions - once retail call buying stops and shorts have covered, the stock can drop 50%+ in days. GME, AMC, BBBY are the playbook.",category:"Options",difficulty:"Advanced"},
{q:"Walk me through a delta hedge on a 10,000-contract short call position as the underlying rallies 10%.",a:"Each call has positive delta (between 0 and 1), and short calls means I'm short delta - I'm hurt as the underlying rallies. 10,000 contracts of 0.5 delta = 500,000 shares short equivalent. To delta hedge, I buy 500,000 shares of the underlying. As the stock rallies 10%, delta of each option moves toward 1 (deeper in the money), so my short call delta moves from -0.5 to maybe -0.7 - I need to buy more stock. That's negative gamma - I'm buying high. Total stock purchased over the rally might be 700,000 shares vs. 500,000 initially. The P&L is bad: I bought stock as it rallied. The reason market makers charge a vol premium (sell calls at higher implied than realized) is precisely to compensate for this gamma drag.",category:"Options",difficulty:"Advanced"},
{q:"If a stock has a binary catalyst (earnings) in 2 days and the ATM straddle prices a 12% move, how do you assess that?",a:"Compare the implied 12% move to the historical earnings move distribution - average earnings move over past 8 quarters, distribution of beats/misses, and what the stock did in similar setups. If historical average is 6%, the market is pricing twice the typical move, which is rich and suggests selling the straddle (collect premium, expect mean reversion). If historical is 15%, the market is underpricing the move and you'd buy the straddle. The hard part is that recent history doesn't always repeat - if there's been a regime shift (sector under stress, accounting concern, management change), historical mean can mislead. Also account for IV crush post-earnings: even if you're directionally right, you can lose money on the vol collapse. The trade is rarely straightforward selling - it's about edge versus the implied distribution.",category:"Options",difficulty:"Advanced"},
{q:"Walk me through how to express a view that AI capex has peaked, using equity derivatives.",a:"Direct expression: long puts or put spreads on hyperscalers (MSFT, META, GOOGL, AMZN) and AI infrastructure names (NVDA, AMD). But these are crowded shorts. Pairs trade: short AI-exposed names vs. long defensive sectors - utilities, staples. Sector dispersion: long SPX vs. short XLK or NVDA-heavy ETFs to capture relative move without taking outright market risk. Volatility expression: long single-stock vol on the hyperscalers (their realized vol should rise if growth disappoints) vs. short SPX vol. Long-dated puts (6-12 month) on the AI basket give you time for the thesis to play out without daily theta bleed. Sizing is small because timing is hard - the thesis can be right but late by 18 months.",category:"Options",difficulty:"Advanced"},
{q:"A client wants to monetize their long equity position without selling. Walk me through what structures you pitch.",a:"Tax efficiency and downside protection are the typical drivers. Covered call: sell OTM calls on the position, collect premium, cap upside above the strike - works if they're neutral to mildly bullish. Collar: sell calls and buy puts to fund the put - caps upside but protects downside, costs little net premium. Equity loan: borrow against the shares at a margin loan rate, deploy elsewhere - keeps full exposure. Variable prepaid forward: get cash today against shares to deliver later, deferring the tax event and capping a portion of upside. Stock equivalent through synthetic options (short put + long call) to reduce capital tied up. The right structure depends on tax basis, time horizon, monetization need, and view on the stock - sales role is to understand all of those before pitching.",category:"Options",difficulty:"Advanced"},
{q:"If you're long 30-day vega and short 90-day vega, what view are you expressing?",a:"I'm long the front of the vol term structure and short the back - I'm betting that near-term vol rises relative to longer-dated vol, or that the term structure flattens or inverts. This is common ahead of binary events (FOMC, earnings, elections) where the market typically prices a vol bump in the front month that fades after the event. The risk is if vol rises broadly across the curve (parallel shift) - I make money on the front but lose on the short back end. The other risk is if vol stays low across the curve and term structure normalizes (front decays faster than back). This is a sophisticated trade that requires understanding event vol pricing and dealer positioning in front-month options.",category:"Options",difficulty:"Advanced"},
{q:"Walk me through what dispersion trading is and when it makes sense.",a:"Dispersion trading bets that individual stock vols will exceed index vols - sell index vol (variance swaps or straddles), buy single-stock vol on the components. The trade profits when stocks move idiosyncratically (low correlation), causing average single-stock realized vol to exceed index realized vol. Makes sense when correlation is elevated (above 0.5-0.6) and likely to decline, often after high-correlation regimes like 2020 or 2022. Doesn't work in true risk-off when correlation goes to 0.9 - that's the failure mode. Capacity is limited because it requires sourcing single-stock vol at fair prices. The trade has positive carry typically (index vol prices in higher correlation than realized), but it's a long-correlation-decline bet.",category:"Options",difficulty:"Advanced"},
{q:"If realized vol over the past 30 days is 8% but implied is 18%, what would you do?",a:"10 vol points of variance risk premium is wide - sellers are getting paid generously. The trade is to sell vol: short straddles, sell variance swaps, or short VIX futures. But the carry is positive precisely because the tail risk is real - a shock can spike realized vol toward implied, blowing out short positions. Sizing has to account for the gap risk. Most blow-up stories on vol selling are picking-up-pennies-in-front-of-a-steamroller setups where the operator was right 95% of the time and lost everything on the 5%. The disciplined version is sell vol but cap downside with deep OTM long puts, or sell vol in size proportional to drawdown tolerance, not expected return.",category:"Options",difficulty:"Advanced"},
{q:"Walk me through how an index rebalance affects flows and how you'd trade it.",a:"Index rebalances (S&P 500 quarterly, MSCI semi-annual, Russell annual) force passive index funds to buy added names and sell deleted ones at the rebalance date - typically the close on the reconstitution date. Names being added typically rally into the rebalance and sell off after, as anticipatory buyers front-run the passive flows. Names being deleted typically sell off into the rebalance and rally after. The trade is long adds and short deletes 1-2 weeks before, unwind into the close. Index rebalance trading is competitive - sell-side desks and prop shops are well aware. The edge has compressed over time but is still meaningful for less-followed indices and smaller-cap rebalances.",category:"Options",difficulty:"Advanced"},
{q:"A pair trade between two close comps starts widening sharply. How do you decide if it's a thesis break?",a:"Pairs trades work on mean reversion - they break when fundamental divergence justifies the spread widening. Decide by looking at the drivers: is there a company-specific catalyst (earnings, M&A, accounting issue) on one leg, or just flow noise? Check both fundamentals (revenue growth, margins, end-market exposure) to see if they're diverging. If the pair has historically reverted within 10 sessions but you're 30 sessions out and still widening, the mean reversion thesis is in trouble. The discipline is hard stops at predefined levels - pair trade losses can run because traders convince themselves the spread will revert. The cleanest exit is when the divergence is no longer just statistical but starts mapping to fundamental differentiation.",category:"Options",difficulty:"Advanced"},
{q:"If correlation between stocks collapses (rho falls), how does that change your dispersion trade P&L?",a:"Falling correlation is the engine of dispersion trade profits - single stocks move idiosyncratically, so single-stock realized vol stays high while index realized vol falls. P&L improves materially: I'm short index vol (which is realizing lower) and long single stock vol (which is realizing higher). The trade is most profitable in regimes where correlation drops from elevated (0.6-0.8) to normal (0.3-0.4). Risk to the trade is correlation spiking back up - typically happens during macro stress or single dominant factor episodes (rate shocks, geopolitical events). The exit is when the correlation differential between index implied and realized normalizes.",category:"Options",difficulty:"Advanced"},
{q:"Walk me through how factor crowding affects equity L/S strategies in stress.",a:"When too many funds are running similar factor exposures (momentum, value, quality, low vol), the positions are positively correlated even if the strategies sound diversified. In stress, when one fund forces deleveraging, the cascade hits all similar positions - that's the August 2007 quant crisis playbook. The signal of crowding is short interest in short legs rising, 13F overlap concentration, and rising borrow costs. When crowding peaks, the unwind is violent - momentum can lose 10-20% in days. The defensive response is reducing factor exposure ahead of the unwind, even if fundamentals haven't changed. Most quant funds have factor exposure limits to manage this, but discretionary L/S often discovers crowding only in the unwind.",category:"Options",difficulty:"Advanced"},
{q:"SPX rallies on bad news. Walk me through three explanations a desk would consider.",a:"First, the news was already priced in - positioning was bearish going in, and the relief that it wasn't worse drives a short squeeze. Second, the news shifts Fed expectations - bad economic news could mean Fed cuts, which is risk-on for equities (bad news is good news). Third, flow-driven dynamics - dealer gamma positioning, systematic strategies (CTA, vol target), buyback flows offsetting fundamental selling. The desk evaluates which is dominant by looking at breadth (rally led by mega-cap or broad?), factor exposure (defensive vs. cyclical), and follow-through over multiple sessions. A bad-news rally that holds for days suggests the fundamentals weren't as feared; one that reverses within 24 hours was flow-driven.",category:"Options",difficulty:"Advanced"},
{q:"If a stock gaps down 15% on guidance and then rallies all day, what are flow-driven explanations?",a:"Several. Quant systematic strategies rotating into bottom-fishing factors that buy after large gap-downs. Short covering - large short positioning gets squeezed as the price doesn't follow through lower. Options market makers who sold puts pre-print are short delta after the gap and have to cover by buying stock. Index funds that need to maintain weighting may buy on the dip if the stock is a major index constituent. Retail flow chasing a cheap price. Algos that detect overshoot patterns. The fundamental explanation also matters - if the guidance cut was conservative and not as bad as feared, smart money may be using the dip to add. The desk wants to see whether the rally holds the next session - sustained recovery suggests fundamentals weren't as bearish as the gap suggested.",category:"Options",difficulty:"Advanced"},
{q:"Walk me through a calendar spread and what view it expresses.",a:"Long calendar: sell short-dated option, buy longer-dated option at the same strike. Net debit position. P&L is maximized if the underlying stays near the strike at the short-dated expiry - the short leg expires worthless while the long leg retains value. View: expect range-bound underlying in the short term, with optionality on a move later. Vega-positive (long the back-month), theta-negative initially but theta-positive after short leg expires. Used to express low-volatility short-term expectation paired with longer-term directional or vol view. Earnings calendars are common: sell front-month vol that's elevated for earnings, buy back month vol that's lower. The trade benefits from vol mean reversion.",category:"Options",difficulty:"Advanced"},
{q:"If buybacks are at record levels and breadth is narrowing, how do you read the market?",a:"Mixed signal. Record buybacks provide consistent flow support to equities - companies are reducing share count, which is mechanically bullish for EPS and stock prices. Narrowing breadth (a few mega-caps driving the index while the rest stagnate or decline) is historically a late-cycle signal - fewer stocks participating means less broad-based earnings strength. The combination often precedes corrections because the index can keep grinding higher on flow while underlying fundamentals weaken. Late-1999, mid-2007, and aspects of 2021 had similar setups. Trade-wise, this argues for downside hedges (cheap because vol is suppressed by buyback flows) and leaning toward equal-weighted index exposure over market-cap-weighted, which is concentrated in the narrow leaders.",category:"Options",difficulty:"Advanced"},
{q:"Walk me through how variance swaps differ from straddles in expressing a vol view.",a:"Variance swaps pay based on realized variance over the swap period, settled in cash - they're pure vol exposure without path dependency. Straddles pay based on the magnitude of the move at expiration - they're path-dependent and have delta exposure that needs hedging. Variance swap P&L is straightforward: realized variance minus strike variance times notional. Straddle P&L depends on stock path and Greeks evolution. Variance swaps are cleaner for expressing pure vol views, especially over longer horizons. Straddles are more accessible (no ISDA needed) and easier to size, but require active delta hedging to isolate vol. Dispersion traders prefer variance swaps because they cleanly separate vol from direction. Most retail and many institutional vol traders use straddles or strangles because of variance swap counterparty access issues.",category:"Options",difficulty:"Advanced"},
{q:"A stock is up 200% YTD and the borrow has gone from 50bps to 25%. What's that telling you?",a:"Borrow costs reflect demand for shorting - 25% borrow means short sellers are paying massive carry, which signals either retail-driven crowded short or genuine fundamental short demand from sophisticated funds. Either way, it makes the short trade economically painful: you need the stock to decline by 25% per year just to break even on borrow. Stocks with extreme borrow rates often see violent short squeezes (GME, AMC) because shorts get forced out by the cost. Conversely, the fundamental case may be very strong on the short side - the question is whether you can withstand the squeeze risk. The trade-off: high borrow signals high conviction shorts but also high squeeze risk. Most desks won't run new shorts above 5-10% borrow except for the very best opportunities.",category:"Options",difficulty:"Advanced"},
{q:"Walk me through how 0DTE options have changed equity market microstructure.",a:"0DTE options (zero days to expiration) on SPX and major ETFs have exploded - they now represent 40-50% of total SPX options volume. Same-day expiry options have very high gamma near the strike, which means dealer hedging flows are concentrated and intraday. This creates short-term price gravity around large 0DTE strike concentrations and can amplify intraday moves when the price breaches key strikes. Realized vol patterns have shifted - implied vol on longer-dated options has compressed relative to historical, partly because retail 0DTE selling supplies vol. Pinning behavior at expiry is more pronounced. The trade implications: SPX intraday can be more mean-reverting near major strikes but break sharply when key levels fail. 0DTE has also created new gamma squeeze patterns in single-name stocks.",category:"Options",difficulty:"Advanced"},
{q:"If you're a market maker quoting a 100k share order, walk me through how you set your bid/offer.",a:"Start with current mid and visible quote - typical institutional spread might be 1-3 cents. For a 100k order on a liquid name (1-2% of ADV), I'd widen my spread to maybe 5-10 cents to compensate for adverse selection risk (info content of the order) and hedging cost. Larger orders get larger spread expansion. I check current dealer positioning - if I'm already long, I'm more aggressive on the bid; if I'm short, I lean my offer. Market conditions: low vol means tighter quotes, high vol means wider. Time of day matters - opening and closing auctions have different dynamics. Algos and SOR (smart order routing) try to slice large orders to minimize market impact. The desk's risk in showing 100k size is the order being part of a larger 1M order, which would force inventory.",category:"Options",difficulty:"Advanced"},
{q:"A client wants to hedge a $500M long equity book through year-end. Walk me through your options structures.",a:"Multiple options. Simple put protection: buy SPX puts at, say, 5% OTM strike, 3-month tenor - cost might be 1.5-2% of notional. Put spreads to reduce cost: buy ATM put, sell 10% OTM put - bounded protection but cheaper. Collar: sell calls to fund the put - costless but caps upside; common for tax-efficient hedging. Variance swap: pay fixed variance, receive realized - pure vol exposure. Tail hedge: very deep OTM puts (20%+ OTM) at fraction of cost, useful as black swan hedge. The right structure depends on the client's view: how much downside protection, willingness to cap upside, time horizon, and cost tolerance. The sales conversation is about understanding their actual constraint, not pitching what's most profitable for the desk.",category:"Options",difficulty:"Advanced"},
{q:"Walk me through what convexity hedging means for equity dealers and when it forces selling.",a:"When dealers are short gamma (typical position around major options expirations or after large institutional put buying), they need to dynamically hedge by buying stock as it rallies and selling as it falls - that's momentum flow. When the market sells off sharply, short-gamma dealers are forced to sell more to maintain delta-neutral, which can accelerate the decline. This is the gamma flip dynamic - at certain SPX levels, aggregate dealer positioning flips from long to short gamma, and the market goes from mean-reverting to trending. February 2018 volmaggedon had this dynamic - VIX ETP rebalancing forced volatility selling that cascaded into broader equity declines. Convexity hedging is a real structural force that contributes to both fast rallies and fast declines.",category:"Options",difficulty:"Advanced"},
{q:"IG spreads are at 75bps and HY at 280bps. What's the trade if you think we're heading into a credit cycle?",a:"Both are tight versus historical, especially HY. HY-IG ratio at roughly 3.7x is in line with averages but reflects benign credit conditions. If a credit cycle is coming, HY spreads will widen disproportionately because default risk reprices. Trades: buy CDX HY protection vs. selling CDX IG (long the HY-IG ratio widening), short HY ETFs (HYG, JNK), buy long-dated puts on equity proxies for HY (regional banks, BDCs). Be careful about timing - spreads can stay tight for 12-18 months before a cycle turns. The trigger is usually a specific catalyst: refinancing wave, default surprise, or central bank shift. Position size assuming the trade can bleed for 6 months before working.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through a CDS-cash basis trade and when it makes sense.",a:"CDS-cash basis is the difference between the CDS spread on a name and the cash bond spread to swaps for the same issuer. In theory they should be equal - both reflect default risk. Basis trades exploit dislocations: when CDS is wider than cash (positive basis), buy the bond and buy CDS protection - collect bond yield, pay CDS premium, but you're funded synthetically and protected against default. Negative basis (cash wider than CDS) is the opposite: sell the bond, sell CDS protection. The trade works when the basis converges back to fair value, often driven by technical flows. Sizing matters - basis can stay wide for months and the trade requires balance sheet to hold both legs. The 2008 crisis saw negative basis blow out to 200bps+ as funded longs had to sell bonds while CDS markets stayed liquid.",category:"Fixed Income",difficulty:"Advanced"},
{q:"If the 2-year yield jumps 20bps on a hot CPI print, walk me through how IG and HY credit react in real time.",a:"Initial reaction is risk-off - equities sell off, credit spreads widen. IG spreads might widen 2-5bps as rates risk-off feeds through, HY widens 10-20bps because lower-quality credit is more sensitive to financing cost increases. The flow is two-pronged: outright credit spreads widen, and rates duration in credit means total return is hit by both higher yields and wider spreads. ETFs (LQD, HYG) see selling pressure that often exceeds underlying market moves, creating ETF-NAV dislocations. Primary issuance windows close immediately - anyone who was planning to issue waits. Secondary trading dries up briefly as desks reassess pricing. Within hours, real money may step in to buy the wider spreads, depending on fundamental view of whether the Fed reaction function justifies the move.",category:"Fixed Income",difficulty:"Advanced"},
{q:"A BBB-rated cyclical sees its CDS spread blow out 100bps in a day with no news. What do you do?",a:"First check for actual news - sometimes there's a delay in reporting (regulatory filing, customer loss, accounting concern). Cross-check single-name CDS against the sector and against the issuer's bonds - is the cash bond moving similarly? Talk to other desks and counterparts to understand if it's positioning-driven or flow-driven. Check broker-dealer inventory and see who's been a marginal seller. Possibilities: rumor mill (legitimate concern even if no official news), large hedger establishing position, structured product unwinds. If you're long, the decision is whether to take the loss or hold conviction. If you're flat, the wider spread is potentially attractive if the move is technical not fundamental. Don't trade on news that hasn't been confirmed, but don't ignore a 100bps move either - the market sometimes knows before the news breaks.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through how you'd hedge a long credit book using IG CDX vs. HY CDX vs. iTraxx.",a:"Match the hedge to the exposure. If the book is predominantly US IG corporates, IG CDX (CDX.NA.IG) is the cleanest hedge - direct beta match. For HY exposure, HY CDX (CDX.NA.HY) is the right instrument. For European exposure, iTraxx Main (IG) or iTraxx Crossover (HY) are the European indices. Imperfect hedges introduce basis risk - hedging US IG with HY CDX gets you wrong-way moves when IG outperforms HY in stress, since HY widens more. Sizing: the hedge ratio is duration-weighted spread DV01 - match the spread DV01 of the long book to the short index notional. Imperfect hedges are sometimes intentional for cost reasons - HY CDX is cheaper to short than IG CDX in calm markets but more volatile in stress.",category:"Fixed Income",difficulty:"Advanced"},
{q:"The dollar strengthens 8% in three months. Walk me through the EM credit reaction.",a:"EM hard currency debt (dollar-denominated) gets hit because the dollar strengthening signals tighter global financial conditions and increases the real burden of dollar-denominated debt for EM issuers. EM local currency debt suffers from the FX translation effect - your dollar return on local debt is hurt by FX depreciation. Spreads widen materially: EM sovereign spreads might go from 350bps to 500bps, EM corporates wider still. The EMBI index typically loses 5-10% in such episodes. Flows reverse - outflows from EM funds accelerate, primary issuance dries up. Within EM, current account deficit countries (Turkey, Argentina, South Africa) suffer most; surplus countries (Korea, Taiwan) hold up better. The 2018 dollar strength episode and 2022 are recent playbooks.",category:"Fixed Income",difficulty:"Advanced"},
{q:"If JGBs sell off 50bps overnight, walk me through the global rates reaction.",a:"Japanese investors are major global rate buyers - when domestic yields rise, they have less reason to reach abroad. Global rates sell off: Treasuries, Bunds, Gilts all hit overnight. USD/JPY drops sharply as the yen rallies on narrowing rate differentials. Cross-currency basis tightens as Japanese demand for FX-hedged Treasury investments weakens. Risk assets typically sell off on global tightening expectations. The 2024 mini-episode with USD/JPY at 160 and BOJ intervention was a preview. The longer-term implication is repatriation of Japanese capital - pension funds, life insurers, and the GPIF have trillions in foreign bonds that could come home if domestic yields offer enough. Watch the spread between 10y JGBs and JGB-equivalent forward USD Treasury yields as the canary.",category:"Fixed Income",difficulty:"Advanced"},
{q:"EUR/USD is at 1.08 and ECB cuts but Fed stays on hold. What's the trade?",a:"Rate differential widens in dollar's favor, so EUR/USD should weaken - short EUR/USD is the textbook trade. Target depends on the magnitude of differential change: if it's a 25bp ECB cut and Fed unchanged, EUR/USD might drop 1-2 cents. But several things could derail it: ECB cut could be already priced; Fed hawkishness could fade if data softens; positioning could be already short EUR, leaving the trade crowded. Confirming evidence: rate differential moving in expected direction, Bund-Treasury spread widening, IG credit spreads diverging in line. The cleaner trade might be paying USD rates vs. receiving EUR rates rather than the FX outright, because rate diff capture is purer than FX which has flow noise.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through carry trade mechanics if you borrow JPY at 1% and invest in MXN at 11%.",a:"Borrow yen at 1%, convert to MXN, invest at 11% - pocket the 10% carry differential. Catch: FX risk. If JPY appreciates 5% against MXN, you've earned 10% carry but lost 5% on FX, netting 5%. If JPY appreciates 20%, you lose 9% on the trade. The trade works in carry-friendly environments - low vol, risk-on, rate differentials stable. It fails violently in risk-off, when funding currencies (JPY, CHF, USD) rally and high-yield currencies sell off. The August 2024 yen carry unwind, January 2008 EM crash, and 1998 Russia/LTCM episode are reminders. Sizing: the trade has positive expected return but fat left tail. Most traders use FX forwards or NDFs and apply leverage that can compound returns or losses. The carry-to-vol ratio is the key risk metric.",category:"Fixed Income",difficulty:"Advanced"},
{q:"If the cross-currency basis turns more negative, what does that say about funding stress?",a:"A more negative basis means dollar funding is more expensive in the FX-implied rate than in the cash dollar market - entities have to pay a premium to source dollars. This signals dollar liquidity stress: typically year-end balance sheet pressure, risk-off events, or banking stress. Specifically, foreign banks face higher costs to hedge their dollar-denominated assets back to local currency. The Fed monitors basis as a real-time funding stress indicator. Wider basis is also tradable - receive USD basis vs. pay yen basis when the dislocation is wide enough. The 2008 crisis saw basis blow out to -200bps, March 2020 -100bps. The Fed's swap lines are designed to relieve these episodes by providing dollars at fixed swap rates to foreign central banks.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through how flight-to-quality works in a global risk-off event.",a:"Risk-off causes capital to flow from risky assets (EM, HY credit, equities) to safe assets (USD, US Treasuries, JPY, CHF, Bunds, gold). The mechanics: forced deleveraging from levered positions, margin calls, fund redemptions. Treasuries get bid - particularly the 10y and 30y as global investors crowd into duration. The dollar rallies because most global trade and financing is dollar-denominated. JPY rallies on carry trade unwinds (yen-funded longs covering). Credit spreads widen materially because everyone wants to reduce credit risk simultaneously. Liquidity in less-liquid markets dries up - emerging market bonds, corporate IG below benchmark size, structured products. The 2008 and March 2020 episodes were the canonical playbooks; subsequent episodes (2022, 2024) have been more orderly because central bank backstops are better understood.",category:"Fixed Income",difficulty:"Advanced"},
{q:"A primary dealer doesn't tender at a Treasury auction. What's that telling you?",a:"Primary dealers are required to participate in auctions, but the size and price of their participation reveal their view on duration. A dealer not tendering (or tendering well below historical) signals concern about taking duration onto their book - either because they're already long, expect prices to fall further, or have limited balance sheet. The market reads weak dealer participation as bearish for the auction, leading to tail and price reaction. Multiple weak auctions in succession can signal structural shifts in foreign demand or domestic real money appetite. Sometimes it's idiosyncratic (one dealer balance sheet issue) and reverses quickly; sometimes it's a leading indicator of a deeper shift. The bid-to-cover ratio is the metric to watch - sub-2.5 is weak, sub-2.0 is concerning.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through the difference between TIPS and nominals when inflation is rising.",a:"TIPS principal adjusts with CPI, so the coupon and final payment rise with inflation - you get real yield protection. Nominal Treasuries pay fixed coupons; if inflation rises, real return falls. Breakeven inflation is the spread between nominal and TIPS yields at the same maturity - the market's expected inflation rate. When inflation is rising, TIPS outperform nominals if the actual rate is above breakeven. The complication: TIPS are less liquid than nominals, have lower duration for the same maturity (because of the inflation accrual), and can underperform if real rates rise faster than breakevens. Trade: long TIPS-short nominals (long breakevens) when you expect inflation to rise; reverse for falling inflation. TIPS also have a small deflation floor on principal that limits downside in deflation scenarios.",category:"Fixed Income",difficulty:"Advanced"},
{q:"If high-yield issuance freezes for 3 weeks, what's the lookahead for credit spreads?",a:"Issuance freezes signal that the new-issue concession (spread over secondary) has widened to a point where issuers are unwilling to pay or investors won't take new paper. It's a flow indicator of stress that often precedes spread widening. Three weeks is unusual - typically issuance pauses for 1-2 weeks around year-end or major events. A longer freeze suggests deeper rebalancing. The lookahead is wider spreads (5-15bps for IG, 25-100bps for HY) as the backlog of unissued paper eventually comes to market when conditions improve, suppressing secondary prices. Trade: short HY ETFs or buy CDX HY protection ahead of the reopen. Watch for issuers with refinancing walls in the next 12 months - they have less flexibility and could be forced into worse pricing.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through how a Mexican peso crisis (1994-style) would unfold today.",a:"Triggers might include current account deterioration, political instability, or external shock (oil decline, US policy shift). The peso starts depreciating, foreign investors pull capital from MXN-denominated bonds (CETES, M-bonds), and Banco de Mexico burns FX reserves to defend. If defense fails, the peso falls sharply (20-40%) over weeks. Inflation rises through import passthrough; rates spike to defend the currency. Domestic banks with dollar-denominated lending and corporates with dollar debt face stress. The 1994 Tequila Crisis contagion spread to other LatAm currencies. Today, Mexico is more developed, has flexible FX regime, better reserves, and IMF backstops are stronger. But the playbook still applies: short MXN, long volatility, long defensive EM currencies that benefit from Mexico stress (BRL, CLP as relative-value).",category:"Fixed Income",difficulty:"Advanced"},
{q:"A corporate has $5B refinancing maturity in 12 months at 4% old rate vs. 7% new. Walk me through the spread impact.",a:"The interest expense jumps from $200M to $350M annually - $150M of incremental interest cost. For a mid-cap company with $500M of EBITDA, that's 30% of EBITDA, which crushes interest coverage and free cash flow. Credit metrics deteriorate: net debt/EBITDA may stay flat, but interest coverage ratio drops from 5x to 2.5x. Rating agencies likely downgrade. CDS spreads on the name widen materially. If the credit is BB+ to BBB-, the downgrade to HY would force forced selling from IG-only funds, accelerating spread widening. The longer the company waits to refinance, the worse the cost - but locking in at 7% might be a 5-year mistake if rates fall. The desk would watch for hedging activity (CDS, rate swaps) that signals what the company is planning.",category:"Fixed Income",difficulty:"Advanced"},
{q:"If liquidity in the off-the-run 10-year drops materially, what's that telling you about market plumbing?",a:"Off-the-run Treasuries (older, less liquid issues) trade at a small yield premium to on-the-run because they're less liquid. When that spread widens, it signals stress in the market plumbing - dealer balance sheet constraints, repo dysfunction, or risk-off demand for the most liquid securities (on-the-run). The September 2019 repo stress, March 2020 Treasury market dislocation, and various year-end episodes all featured off-the-run premium widening. Trade: receive off-the-run, pay on-the-run - basis trade that converges back. Sizing matters because the trade can take weeks to revert and requires balance sheet. The deeper signal is that market makers don't have the capacity to arbitrage the dislocation, which means broader market liquidity is impaired.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through how repo rates spiking signal money market stress.",a:"Repo rates are the overnight cost of borrowing against Treasury collateral - when reserves are tight, banks bid aggressively for cash, pushing repo rates above the Fed's target range. The September 2019 episode saw overnight repo spike from 2.2% to 10% in hours as quarter-end corporate tax payments and Treasury settlements drained reserves, forcing the Fed to intervene with emergency repo operations. Repo rate spikes indicate the banking system can't absorb funding shocks without Fed intervention. The signals to watch: SOFR diverging from IOR, repo-OIS spread widening, FX swap basis blowing out simultaneously. Trade implications: short-term front-end rates volatility, potential Fed policy response (slowing QT, expanding repo facilities). Now the Fed runs a standing repo facility specifically to prevent these episodes.",category:"Fixed Income",difficulty:"Advanced"},
{q:"EM central bank intervenes to defend currency. Walk me through the second-order effects.",a:"FX intervention burns reserves - central bank sells dollars and buys local currency. Effective in the short term but unsustainable if reserves are limited. Higher local rates often accompany intervention to incentivize holding the currency, which hurts domestic growth and equity markets. Foreign capital sees intervention as a defensive signal - sometimes confidence-restoring, sometimes a sign of weakness. The decision tree is whether the intervention is supported by fundamentals (improving current account, fiscal discipline) or fighting a losing battle. The 1997-1998 Asian crisis saw multiple central banks burn reserves trying to defend pegs before capitulating. Today, intervention combined with rate hikes and policy adjustments is more common. Trade: fade the intervention if fundamentals are weak (continue shorting the currency); follow the intervention if it's backed by real policy adjustment.",category:"Fixed Income",difficulty:"Advanced"},
{q:"If you're trading the front-end Eurodollar curve and you expect a Fed surprise, what's your trade?",a:"Eurodollar futures (now SOFR futures since 2023) price the path of short-term rates. If you expect the Fed to be more dovish than priced, buy front-month SOFR futures - payoff if rates fall faster than the curve implies. Reverse for hawkish surprise. The red pack (next 12 months) is most sensitive to near-term Fed expectations. Sizing: front-end has high DV01 per bp, so a 50bp surprise can move SOFR Mar contract 50 ticks (each tick is 0.005% of $1M notional = $12.50). Risk management: stop-losses on the position because surprises move violently. Steepener vs. flattener trades (calendar spreads between contracts) reduce outright duration risk and isolate the curve shape view. The Eurodollar curve historically priced the Fed wrong - being able to trade against a wrong curve is one of the most profitable spots in macro.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through a corporate spread duration hedge for a long-only credit fund.",a:"Spread duration is the sensitivity of bond price to changes in credit spread. A 5-year IG bond has roughly 5 spread DV01 - for every 1bp widening, price drops 5bps. To hedge a $1B IG book with average 5y spread duration, you need to short $1B notional of equivalent spread duration. Cheapest option is CDX IG (NA.IG) - short the index gives credit beta hedge. Alternative is single-name CDS on the largest issuer concentrations. The basis risk is the index doesn't match book composition perfectly. Calculate the cross-correlation between book returns and CDX returns to determine hedge ratio. Hedge ratio typically 80-100% for IG books well-correlated with CDX. For HY books, similar mechanics with CDX HY. Rebalance the hedge as spread duration drifts.",category:"Fixed Income",difficulty:"Advanced"},
{q:"If a sovereign CDS is pricing 30% default probability but bonds trade at 70 cents, what's the trade?",a:"Implied recovery rate is roughly: (1 - default prob) x 100 + default prob x recovery = 70, so recovery is implied around 57. CDS pricing assumes a different recovery (often 40% standard for senior unsecured). The mismatch creates a basis trade: if bonds are pricing higher recovery than CDS, you can buy bonds and buy CDS protection - at default, you get bond recovery (57) and CDS payoff (60 minus delivery), netting more than bond price suggests. The trade also captures any spread tightening if conditions improve. Sizing: large notional but limited downside (recovery floor). Risk: recovery assumption could be wrong, CDS settlement mechanics could differ, restructuring vs. hard default determines outcome. Sophisticated sovereign credit desks trade these basis trades regularly.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through how distressed debt trading differs from IG and HY trading.",a:"Distressed debt (typically bonds trading below 70 cents) is event-driven - recovery in restructuring or default is the main P&L driver, not spread movement. Liquidity is much worse, with wide bid-ask spreads (1-5 points). The buyer needs to assess: capital structure priority, asset coverage, recovery scenarios under different restructuring outcomes (in-court Chapter 11 vs. out-of-court). Legal expertise matters as much as trading skill - covenants, indentures, intercreditor agreements determine recovery. Time horizon is longer (6-24 months typically). Position sizes are smaller because liquidity is limited. The hedge fund and prop shop ecosystem is different - distressed specialists like Oaktree, Apollo, Centerbridge dominate. Trading distressed requires both market-making instincts and credit fundamental analysis.",category:"Fixed Income",difficulty:"Advanced"},
{q:"If a major bank's CDS suddenly widens, walk me through what the desk does.",a:"Bank CDS widening signals counterparty risk concerns. The desk immediately checks: is it idiosyncratic (this bank specifically) or sector-wide; what's the rumor versus fact; is there a hedging or positioning unwind. Operational response: review exposure to the bank as counterparty in OTC derivatives, prime brokerage, securities lending, FX trades. Reduce or terminate unsecured exposure if possible. Adjust credit lines, demand more collateral. If the widening is fundamental (bank actually has issues), this could be the start of a 2008-style cascade - short bank equity, long banking sector CDS, long financial sector volatility. If it's a rumor, fade the move once it's confirmed false. Bank stress is fast-moving and can become systemic in days, so the response has to be immediate.",category:"Fixed Income",difficulty:"Advanced"},
{q:"Walk me through how you'd construct a relative value trade between a US 10y and a German Bund.",a:"The trade expresses a view on the US-Germany rate spread. Currently, US 10y at 4.2% and Bund 10y at 2.4% - spread of 180bps. If you think the spread is too wide (US to outperform Germany), buy US Treasuries and sell Bunds in equal DV01 amounts. If too narrow, reverse. Drivers of US-Germany spread: relative growth, central bank divergence, fiscal trajectories, inflation expectations, term premium differentials. Sizing on DV01-neutral basis isolates the spread from level. The trade has carry implications - US 10y yields more than Bunds, so being long US gives positive carry. Watch for trade reversal triggers: ECB shift toward hawkishness, US recession deepening, sovereign credit concerns in either country. Most macro funds run some version of this trade as part of their global rates book.",category:"Fixed Income",difficulty:"Advanced"},
{q:"OPEC announces a surprise production cut of 1mb/d. Walk me through the cross-asset reaction in 24 hours.",a:"Oil rallies $5-10/bbl in minutes on the headline. Energy equities (XLE, XOM, CVX) gap up 3-5%. USD weakens because oil-importer currencies are pressured but commodity-exporter currencies rally (CAD, RUB, NOK). Inflation breakevens widen on the implied inflation impulse, pressuring duration. Treasuries sell off as nominal yields rise on the inflation pass-through. Equities are mixed - energy strong, transports and consumer cyclicals weak. Within 24 hours, second-wave moves: airlines and shippers underperform on fuel cost concerns, refiners may underperform if crude rallies faster than products. The trade going in: long energy equities, long oil futures, short consumer cyclicals; if the cut surprises, those positions get paid significantly.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"If WTI moves from $80 to $50 in three months, walk me through the impact on USD/CAD, energy HY credit, and EM sovereigns.",a:"USD/CAD rallies (CAD weakens) because Canadian terms of trade deteriorate - oil is a major export. Could see USD/CAD from 1.35 to 1.45 over the move. Energy HY credit gets hammered - spreads on Permian and Bakken producers widen 200-500bps; covenant concerns rise; refinancing risk increases for highly levered producers. EM sovereigns split: oil exporters (Russia, Saudi Arabia, Angola, Nigeria) see spreads widen and currencies fall; oil importers (India, Turkey, Korea) benefit through lower import bills and improved current accounts. The 2014-2016 episode is the playbook - Saudi Arabia burned reserves, Russia let the ruble devalue, and the US shale industry went through a default cycle that took several years to resolve.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"Walk me through how you'd express a view that commodity supercycle is ending.",a:"Multiple expressions. Direct: short commodity futures (long-dated, lower carry impact), short commodity-levered equities (mining, energy), short commodity-exporter currencies (AUD, CAD, BRL). Inflation expression: short long-dated breakevens or TIPS as inflation expectations come down. Cross-asset: long defensive equity sectors (staples, utilities) that benefit from lower input costs, vs. short cyclical materials/industrials. China exposure: short A-share materials sector since China demand is a key driver of commodity supercycles. Timing is hard - supercycles have lasted years and reversed years. The asymmetric expression is options: long-dated puts on copper, oil, BHP, FCX provide convex downside exposure. Sizing accounts for the fact that you might be right but early by 12-24 months.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"If gold rallies 15% while real yields rise 50bps, what's going on?",a:"Textbook says gold should fall with real yields rising - gold is a non-yielding asset and competing real rates make it less attractive. Decoupling suggests other forces dominate: central bank buying (China, India, Russia adding to reserves), geopolitical risk premium (war, sanctions), de-dollarization theme, or hedge against currency debasement. The gold-real yield correlation has been breaking down since 2022 as central bank flows became dominant marginal buyers. Trade implication: gold is no longer just a real-rate hedge; it's responding to structural FX reserve management. Position sizing should reflect the changed regime - gold can rally independently of rates, but the relationship could reassert. Watch ETF flows, central bank reserves data, and physical gold premiums in Asian markets as indicators.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"Walk me through natural gas seasonality and why winter weather can move TTF or Henry Hub 50% in a week.",a:"Natural gas demand peaks in winter for heating, and supply is relatively inflexible - storage levels are the buffer. When storage runs low and weather forecasts cold, prices spike. Henry Hub (US benchmark) typically peaks in January-February. TTF (European benchmark) was historically more stable but became volatile after 2021-2022 Russia disruption. Storage withdrawal patterns matter - entering winter with low storage means any cold snap drives panic buying. The 2021 European gas crisis saw TTF go from €15/MWh to €300/MWh as Russian supply cuts coincided with low storage and high demand. Trade: long winter gas futures with stop-loss discipline because volatility is enormous; storage spread trades (summer-winter calendar spreads). Watch weather models, storage reports, and LNG flow data.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"If the crack spread widens dramatically, who wins and who loses?",a:"Crack spread is the price of refined products (gasoline, diesel) minus the price of crude - it's the refiner's gross margin. When it widens, refiners win (VLO, PSX, MPC) - higher margins on their core business. Crude producers don't directly benefit unless they're integrated (XOM, CVX have refining segments). Consumers lose at the gas pump. The winners on the equity side are pure-play refiners and integrated majors with high refining exposure. The losers are anyone who consumes refined products (airlines, trucking). The widening typically happens during refinery outages (supply constraint), demand spikes (driving season, geopolitical fears), or imbalances between crude grades. Trades: long refiner equities (VLO, MPC), short airline equities (DAL, UAL) when crack spreads widen meaningfully.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"Walk me through how China stimulus would transmit across copper, iron ore, and oil.",a:"China consumes 50%+ of global copper and iron ore, and is a major oil importer. Stimulus targeting infrastructure or property would boost copper and iron ore most directly through construction demand. Iron ore historically moves 30-50% on major Chinese stimulus announcements. Copper moves 15-25% - slightly less direct but still major. Oil benefits but less dramatically because Chinese stimulus is rarely the marginal oil price driver - global demand and OPEC matter more. Equity expressions: BHP, RIO, VALE benefit most from iron ore; FCX from copper; energy majors less direct. Currency: AUD, BRL, CAD all benefit. The 2008-2009 China stimulus drove the supercycle phase 2; the 2015-2016 supply-side reform was similarly impactful. Time horizon matters - announcement effects are immediate, but actual demand transmission takes 6-12 months.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"If shipping rates (BDI) spike 100% in a month, what's that telling you?",a:"The Baltic Dry Index tracks rates for dry bulk shipping (iron ore, coal, grain). A 100% spike signals either demand surge (China stimulus, restocking cycle), supply constraint (port congestion, vessel shortage), or specific commodity demand (iron ore stockpiling). The signal cascade: rising BDI often precedes commodity price rallies and is a leading indicator of global trade activity. The 2020-2021 spike saw BDI go from 500 to 5000+ on supply chain disruptions and demand recovery. Trade implications: long shipping equities (SBLK, GOGL, DSX), long bulk commodities (iron ore, copper), long commodity exporter currencies. Watch for divergence between BDI and other shipping indices (CCFI for containers, dirty/clean tanker indices) - segment-specific spikes vs. broad-based moves.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"Walk me through how to think about agricultural commodity sensitivity to weather and geopolitics.",a:"Agricultural commodities have inelastic short-term supply because crops have annual cycles. Weather disruptions (drought, frost, flood) in major producing regions (US, Brazil, Argentina, Russia, Ukraine) can move prices 30-50% in weeks. Geopolitical disruptions in Black Sea (Russia, Ukraine wheat and corn), Mississippi River, or Suez Canal create global supply shocks. Demand is more stable - food is essential, but biofuel demand (corn for ethanol, soy oil for biodiesel) is policy-sensitive. Trade structure: long-dated futures less volatile than nearby; calendar spreads to express timing views; equity expressions (Deere, Cargill, fertilizer producers like CF, MOS, NTR). Volatility is regime-dependent - quiet decades and panic decades. The 2022 Ukraine war drove wheat to all-time highs; 2012 US drought similarly.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"If corn and wheat both spike on a Black Sea conflict, walk me through second-order trades.",a:"First-order trade is long wheat and corn futures, captured immediately. Second-order trades: long fertilizer producers (CF, MOS, NTR) as Russia is a major fertilizer exporter and supply concerns drive prices. Long agricultural equipment (Deere, AGCO) as farmers ramp planting. Long ethanol producers (ADM) as corn prices rise. Short emerging markets that import grain (Egypt, Indonesia, sub-Saharan Africa) as food inflation hits political stability. Long defensive consumer staples that have pricing power. Long EM food security plays (Indian, Brazilian agriculture). Currency trades: long BRL, ARS, AUD as agricultural exporters benefit; short food-importer currencies. The 2022 war playbook saw all these trades work in succession over 6-12 months. Position management: take profits as the initial spike fades and structural supply adjustments begin.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"Walk me through how gold trades during a banking crisis vs. a sovereign debt crisis.",a:"Banking crisis (2008, March 2023 SVB): gold initially sells off in the panic as forced sellers liquidate to meet margin calls or fund redemptions, then rallies sharply as Fed cuts rates and prints money to stabilize the system. The first 1-2 weeks can see gold down 10%, then rally 30-50% over months. Sovereign debt crisis (Eurozone 2011-2012, EM crises): gold rallies more directly as a flight-to-quality alternative to the affected currency, especially if it's a major reserve currency. Eurozone crisis saw gold rally from $1200 to $1900 in 12 months. The distinction matters: banking crises are dollar-positive (flight to liquid USD), sovereign crises can be dollar-positive or negative depending on which sovereign. Both ultimately drive gold higher through central bank response, but the path differs.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"If WTI is at $80 and the back end of the curve is at $60, what's that structure telling you?",a:"Backwardation - front-month above longer-dated, signals near-term tightness with expected supply rebuilding. Backwardation generates positive roll yield for long positions (you sell the higher front-month, buy lower back-month - collect the difference). Drivers: low inventories, geopolitical supply concerns, OPEC discipline, or strong near-term demand. The opposite (contango) signals oversupply or storage demand. Trade implications: backwardated markets reward long positioning through carry, even if spot prices stay flat. Equity proxies (XLE) benefit similarly. Watch for curve flattening as a leading indicator of demand softening or supply rebuilding - if back end starts catching up to front, the bull thesis is weakening. The 2014-2016 transition from backwardation to deep contango preceded the oil crash.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"Walk me through how a strong dollar affects commodity prices structurally.",a:"Commodities are predominantly priced in dollars, so a stronger dollar mechanically reduces commodity prices for non-dollar buyers - demand from non-US consumers softens. Production costs are mixed: producers in dollar-bloc countries benefit (lower input costs in local terms), but globally-priced commodity revenue falls. Supply response: producers with high cost bases get squeezed; low-cost producers gain market share. Inventory dynamics: stronger dollar reduces speculative interest in commodity-as-store-of-value, leading to inventory liquidation. The 2014-2016 dollar strength contributed to the oil and commodity crash. Trade: when dollar starts rallying meaningfully (DXY breaking range), expect commodities to weaken with a lag. Short copper, long DXY is a common cross-asset trade. Reverse during dollar weakness - long commodities, long EM, short dollar.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"If oil and equities decouple (both fall together), what's that telling you?",a:"Normal regime: oil and equities are positively correlated through growth - both reflect global activity. When they fall together, it often signals: liquidation event (forced selling across asset classes), recession fears (demand destruction), or central bank tightening surprise. Liquidation events typically last days to weeks before correlations normalize. Recession-driven decoupling can last months as growth expectations re-rate. The trade implications: long volatility across asset classes (correlations spiking means broader stress), short cyclicals, long defensives. The 2008 and March 2020 episodes saw equities and oil down 30-50% together. The post-COVID period saw equities and oil rally together. Watch what comes next: continued correlation breakdown or normalization. Sustained equities-oil decline is typically a recession signal.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"Walk me through how power markets price extreme weather events and where the dislocations show up.",a:"Power markets have very short-term price discovery - day-ahead and real-time markets. Extreme weather (heat waves, polar vortex) creates demand spikes that can move prices 1000-10000% in hours. Texas (ERCOT) February 2021 saw prices hit the cap of $9000/MWh for days, bankrupting some retail providers. Dislocations: physical natural gas spikes ahead of power (heating demand spikes first); regional spreads widen as transmission constrains; renewable underperformance during extreme cold (frozen turbines) creates supply gaps. Trade exposures: long winter natural gas in extreme cold scenarios; long power producers with reliable thermal generation; short consumer-facing retail providers without hedging. Risk management is critical - exposures can blow up in hours, not days. Most power trading is concentrated at specialized desks given the technical complexity.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"If a major refinery has an unplanned outage, walk me through how that affects gasoline cracks and crude differentials.",a:"Gasoline supply tightens immediately - wholesale prices spike, refiner crack spreads widen as gasoline rallies relative to crude. Crude differentials widen - the type of crude the refinery normally processes faces excess supply (price falls), while crudes that other refineries can process get bid. Regional impacts: Gulf Coast refinery outages affect WTI-Brent spreads and gasoline differentials between regions. Tankers reroute, freight rates respond. Hurricane-driven outages (annual Gulf Coast risk) have predictable patterns. Trade implications: long gasoline cracks (RBOB minus WTI), short specific crude grades that the disabled refinery consumed, long refiner equities with healthy operations. Outage duration matters - short outages (1-2 weeks) get bid back, long outages (months) create persistent dislocations.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"Walk me through how commodity producer equities (XOM, BHP) decouple from spot commodity prices.",a:"Producer equities reflect production volume, costs, capital structure, and management decisions, not just commodity prices. Decoupling drivers: hedging programs (locked-in prices for 6-18 months), production growth or decline, cost inflation/deflation (services costs, labor), capital allocation (buybacks, dividends, capex). At high commodity prices, producers can underperform if management is undisciplined (overspending on capex, bad M&A). At low prices, low-cost producers outperform peers. ESG factors increasingly affect long-term multiples. XOM in 2024-2025 with disciplined capital allocation outperformed many smaller E&P names even as oil prices were range-bound. The trade lesson: don't assume producer equities and spot commodities are interchangeable. They have idiosyncratic drivers and can decouple for extended periods.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"If TTF (European natural gas) spikes while Henry Hub stays flat, walk me through what's happening.",a:"Regional natural gas markets are separated by transportation constraints - LNG (liquefied natural gas) is the bridge. A TTF spike without Henry Hub move signals European-specific supply disruption (Russia, Norway, North Sea outages) or demand surge (cold snap). LNG arbitrage: high TTF attracts US LNG cargoes, eventually pulling Henry Hub higher with a lag. But the spread can stay wide if LNG export capacity is constrained. The 2021-2022 European energy crisis saw TTF go to €300/MWh while Henry Hub stayed below $10/MMBtu - extreme dislocation that persisted for over a year. Trade: long TTF, short Henry Hub if you see regional supply shock; long LNG-exposed equities (Cheniere, Tellurian); long European utilities with regulated pricing; short energy-intensive European industrials (chemicals, steel).",category:"Trade Ideas",difficulty:"Advanced"},
{q:"Walk me through how an inventory cycle in semis or steel transmits through equity sectors.",a:"Inventory cycles are major drivers of cyclical equity returns. Building phase: customers order ahead of demand; revenue and earnings overstate underlying activity; producer equities outperform. Peak: inventory builds to excessive levels; customers start cutting orders; revenue and earnings collapse faster than spot prices. Destocking phase: producers cut prices to clear inventory; customer destocking compounds the downturn. Recovery: inventory normalizes; orders return; cycle restarts. Semis (NVDA, AMD, MU, AMAT) follow this 24-36 month cycle. Steel (Nucor, Cleveland Cliffs) similarly. Trade: short producer equities going into peak (signaled by lead time normalization, customer inventory buildup); long going into trough (signaled by destocking completion). Memory chips (DRAM, NAND) have particularly violent cycles. The 2018-2019 semi cycle and 2022-2023 cycles are recent examples.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"If China's PMI prints below 50 for three consecutive months, walk me through the commodities trade.",a:"Below 50 PMI signals contraction. Three months sustained means real economic weakness, not noise. Commodities exposed to Chinese demand (copper, iron ore, oil to lesser degree) face downside risk. Trade: short copper futures or producer equities (FCX, BHP); short iron ore producers (BHP, RIO, VALE); long China defensive proxies (utilities). Currency: short AUD, BRL as commodity export proxies. Equity sector: short global materials, short emerging markets that export to China. The risk to the trade is China stimulus response - historically, sustained PMI weakness triggers fiscal or monetary easing within 3-6 months, which reverses commodity selling. 2015-2016, 2018-2019, 2022 all saw China stimulus cycles following PMI weakness. Sizing should be measured because the reversal is often violent.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"Walk me through how a cross-asset crisis (like March 2020) creates correlation regime shifts.",a:"In normal regimes, assets have different drivers - equities respond to earnings, bonds to rates, commodities to supply/demand, currencies to rate differentials. In crisis, forced deleveraging dominates all asset classes - margin calls force selling of whatever can be sold, regardless of fundamentals. Correlations spike toward 1 across risk-on assets and toward -1 between risk-on and safe assets (USD, Treasuries, gold in some episodes). Diversification benefits collapse exactly when needed. Trade implications: long volatility across asset classes pays off; correlation trades (dispersion) get hit. The 2020 March episode saw equities, credit, gold, oil all fall together in mid-March before central bank intervention. Sizing for tail risk has to assume correlation can flip - VaR models calibrated to normal regimes systematically underestimate risk in crises.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"If oil rallies but oil-levered equities don't, walk me through what's happening.",a:"Equity-commodity decoupling signals factors beyond spot prices. Possibilities: equity market broader weakness (cyclical rotation against value/energy), specific company concerns (regulation, operations), capital allocation skepticism, ESG flows reducing energy exposure, or hedge book mark-to-market losses offsetting commodity gains. In 2020-2022, energy equities lagged oil prices significantly as ESG flows pulled capital despite improving fundamentals. The trade: if you believe the decoupling is temporary, long energy equities (XLE, XOM) is attractive; if structural, the underlying signal is bearish for energy. Watch fund flows, ETF holdings, and analyst rating changes. The 2022-2023 energy equity rally eventually caught up to commodity moves as fundamentals dominated. Decoupling rarely persists more than 12-18 months.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"Walk me through how you'd hedge inflation through commodities vs. TIPS vs. real estate.",a:"Each hedge has different mechanics and characteristics. Commodities: direct exposure to inflationary inputs (oil, copper, agricultural), high volatility, no carry, capital appreciation only when prices rise. TIPS: explicit CPI adjustment to principal and coupon, low volatility, modest real yield, regulated by Treasury market mechanics. Real estate: rental income often inflation-linked, capital appreciation tied to nominal growth, less liquid, large transaction costs. Commodities tend to lead inflation cycles (oil and copper move ahead of CPI prints), TIPS coincident (settle on CPI), real estate lagging. Hybrid hedge: 40% TIPS, 30% commodities, 30% real estate gives diversified inflation exposure across time horizons. The 2021-2022 inflation episode showed all three working: commodities up 50%+, TIPS positive real returns, real estate strong before rates broke it.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"If gold and bitcoin are negatively correlated, walk me through the implications for hedge fund positioning.",a:"Gold and Bitcoin both serve as alternative store of value assets, often hyped as inflation/debasement hedges. If they're negatively correlated, it means they're responding to different drivers - perhaps gold to central bank flows and traditional risk-off, Bitcoin to technology/retail flows and risk-on. The implication: they're not substitutes; they're different assets that happen to share a marketing narrative. Hedge funds positioning in digital gold need to revisit the thesis. The correlation has varied: positive during 2020-2021 inflation hedge narrative, negative during 2022 as Bitcoin sold off with tech while gold held up. Trade: when correlation is negative, you can run both as separate exposures rather than treating them as one trade. Risk: correlation can flip back to positive during a true debasement event.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"Walk me through carry trades in commodities - what's contango carry, what's backwardation, and when do they reverse?",a:"Carry in commodities comes from roll yield as futures contracts roll forward. Backwardation: front-month higher than back-month; long futures positions earn positive roll yield as front-month rolls down the curve toward expiry. Contango: front-month lower than back-month; long positions lose money on roll. Backwardated commodities (typically oil during tight supply, copper during deficits) reward long carry traders. Contango commodities (typically gold, agricultural during surplus) penalize long carry. Reversals happen when supply-demand fundamentals shift: backwardation flips to contango on oversupply (oil 2014-2016, 2020) or rebuilding inventories. Contango flips to backwardation on supply tightness. Trade implications: passive commodity index investors get hurt in contango (USO during 2020 negative oil); active managers can rotate based on curve shape. Sizing should account for carry, not just spot direction.",category:"Trade Ideas",difficulty:"Advanced"},
{q:"Walk me through how you'd handle a position that's down 30% and your conviction has weakened.",a:"First step is honest reassessment: re-do the analysis as if I were entering today at current prices. If conviction is genuinely lower, the position needs to be cut regardless of P&L - anchoring on entry price is one of the worst trading sins. The size of the cut depends on how much conviction has weakened: 50% lower conviction = 50% smaller position. If I'm flat conviction but want optionality, I might cut to 25% and set tight rules for adding back if the original thesis re-establishes. The discipline is that loss size doesn't matter for the decision - only forward expected return does. Many traders hold losers hoping to get back to even, which is the path to compounding losses. The post-mortem comes later - focus on the next trade now.",category:"Behavioral",difficulty:"Advanced"},
{q:"You have a trade that's working but you keep wanting to take profit. How do you discipline that?",a:"Pre-commitment is the answer. Before entering, write down profit targets at specific levels and stick to them - no discretionary cutting because of euphoria. Multi-level exits help: take 1/3 off at first target, 1/3 at second, let the remainder run with a trailing stop. The want to take profit urge usually reflects fear of giving back gains, not changed fundamentals. The cleanest discipline: if your thesis is still intact and you'd put on the trade fresh at current levels, don't cut. If thesis is no longer compelling, cut entirely. Half-measure thinking - just take some off because it's been a great trade - destroys long-term returns. Letting winners run is where most traders make their year.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how stop-loss orders can be both a discipline and a trap.",a:"Discipline: stops enforce the rule that wrong trades have to be cut. Without stops, traders fall into hope mode and let losers compound. They size positions assuming the stop is real downside, which is essential for risk management. The trap: stops are visible in the market, particularly cluster around round numbers and obvious technical levels. Market makers and short-term traders can run stops by pushing through key levels, creating a brief liquidity vacuum that triggers cascading stop hits. The trade lesson: place stops based on your thesis breakdown levels, not arbitrary percentages; consider mental stops with manual execution if your size is large enough to be a target; size positions so a normal stop-out is a small portion of capital. The trap is real but the discipline benefit outweighs it for most traders.",category:"Behavioral",difficulty:"Advanced"},
{q:"If your VaR is breached on a portfolio, walk me through what you do.",a:"First, understand why - was it a market move, a position change, or a model recalibration? Verify the calculation isn't a data error. If genuine, the desk has to reduce risk to come back inside the limit, often within 24 hours. The decision is which positions to cut: largest contributors to VaR, lowest-conviction positions, most liquid (easiest to exit), or those with the worst forward risk-reward. Speak to risk and management about the cause - sometimes a 1-day vol spike can resolve without forced selling. Conduct a post-mortem: was the VaR limit appropriate, is the model capturing the right risks, was the position sizing too aggressive. VaR breaches are rare for well-managed books - recurring breaches indicate a structural issue that needs fixing, not just rebalancing.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how you'd size a high-conviction trade vs. a low-conviction one.",a:"Kelly criterion gives a rough framework: position size proportional to edge and inversely proportional to variance. In practice, high-conviction trades might be 2-3x larger than low-conviction. But size has to account for: portfolio diversification (don't put 50% in one trade even if conviction is sky-high), liquidity (can you exit the position?), correlation with existing positions, and tail risk. A high-conviction trade in an uncorrelated, liquid name might be 5% of capital; a high-conviction trade in a correlated, less-liquid name might be 1%. The discipline is to be honest about conviction - many traders fool themselves into thinking everything is high-conviction. Sizing should reflect the realistic distribution of outcomes, not the bull case alone.",category:"Behavioral",difficulty:"Advanced"},
{q:"If you're a market maker and a client wants to buy 10x your average daily volume, how do you price it?",a:"Massively wide quote. If average bid-ask is 5 cents and daily volume is 100k shares, a 1M share order requires widening to maybe 25-50 cents on both sides to compensate for: market impact (the order itself will move the market against you as you hedge), inventory carrying cost (you'll have to sit on the position before you can lay it off), information content (large orders signal someone has a view), and balance sheet usage. The pricing also depends on how I think about the next few hours/days - can I work the order in slices? Am I in a position to take on the risk given my book? Sometimes the right answer is I can't price that size right now if it would create too much directional risk. Trust matters - if this is a long-term client and the order isn't toxic, you might tighten the quote to win the relationship.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how implied vs. realized vol divergence informs your sizing.",a:"When implied vol is much higher than realized (vol risk premium positive), short vol is statistically attractive but tail risk is real. Size positions assuming you could lose 3-5x the expected return in a vol spike - the asymmetric payoff cuts hard against you. When implied is at or below realized (vol underpriced), long vol is statistically favorable, but the carry drag means you can bleed for months waiting. Size accordingly: smaller short vol positions when premium is moderate, larger when wide; smaller long vol positions because of carry, larger when implied is genuinely cheap. The classic mistake is sizing short vol to maximize Sharpe in calm markets - works for years then blows up. February 2018 volmageddon and August 2024 yen unwind are reminders.",category:"Behavioral",difficulty:"Advanced"},
{q:"A trade you put on for one reason is working for a different reason. What do you do?",a:"Be honest about it. The trade working doesn't validate the thesis - the right outcome for the wrong reason is just luck. Reassess: is the actual driver something you understand and could have anticipated? If so, you got fortunate but the principle of the trade is sound. If the driver is something you didn't see, you don't actually understand the position, and the next move could be against you for reasons you don't grasp. The disciplined response is often to take profit and step back to study the actual driver before re-entering. Long-term performance comes from process, not outcomes - letting yourself rationalize lucky wins as skill is how you build false confidence and oversized positions in the next trade.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how you'd handle a black swan event on a leveraged book.",a:"First priority is survival - maintain margin, manage liquidity, avoid forced selling. Check immediate counterparty risk and operational issues (broken trades, system outages). Reduce the most liquid leg of correlated positions first to free up capital and reduce gross exposure. Don't try to bottom-fish during the panic - opportunities will be there for days. Communicate with risk management, compliance, and senior leadership immediately. Document the event for the post-mortem. Black swan events typically have a phase 1 panic and a phase 2 recovery - survivors in phase 1 win in phase 2. The pre-event preparation matters more than in-event reactions: pre-arranged credit lines, hedging programs, stress-tested scenarios. Most blown-up traders fail because they didn't prepare, not because they reacted slowly.",category:"Behavioral",difficulty:"Advanced"},
{q:"If your trade has 5:1 reward/risk but only 15% probability of working, do you take it?",a:"Expected value: 0.15 x 5 - 0.85 x 1 = 0.75 - 0.85 = -0.10. Negative expected value - don't take it. The reward/risk ratio looks attractive but probabilities matter equally. Many traders over-weight reward/risk and under-weight probability, especially on home-run trades. The discipline is to size every trade by expected value, not just one side of the equation. A 2:1 reward/risk at 50% probability (EV = 1.0 - 0.5 = 0.5) is much better than 5:1 at 15%. The mental error is being seduced by the upside without doing the math on the downside frequency. Position size should also be adjusted for the variance of the outcome - high-variance trades (binary catalysts) require smaller sizing even at positive EV.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how to distinguish noise from information when prices move against you.",a:"Noise: small moves, no news, no follow-through, reverses within 1-3 sessions. Information: large moves, accompanying volume, news flow, broad-based participation across correlated assets, follow-through over days. Other tells: bid-ask widening (uncertainty), block trades (real money positioning), correlated moves in other instruments (sector-wide). The discipline is to write down your noise tolerance before entering - I'll cut if down 5% with no news, 10% if there's news that breaks the thesis. Without pre-commitment, you'll rationalize every move as noise on the way down. The opposite trap is being too jumpy - every 2% move shouldn't cause a position change. Develop the muscle of waiting 1-3 sessions before reacting to ambiguous moves.",category:"Behavioral",difficulty:"Advanced"},
{q:"If a sell-side analyst's view aligns with yours, do you trust it more or less? Why?",a:"Slightly less if anything. Sell-side analysts have access constraints (no insider trading, work with company management), incentive issues (banking relationships, axe positions), and crowd dynamics (they often herd toward consensus). Their alignment validates your view is conventional, which can mean it's already priced. The variant perception edge requires being differentiated from sell-side consensus. That said, top-rated analysts with proprietary research and good track records add real value - the alignment is more meaningful from a Goldman analyst who has historically had differentiated calls than from a junior analyst at a small firm. The right question: does the alignment come from the same evidence or different evidence? If different, your view is reinforced; if same, you may be in a crowded position.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how desk crowding shows up in microstructure data.",a:"Several microstructure signals. Short interest in short legs rising - implies many people are running the same long-short factor exposures. Borrow costs rising for specific names - high demand to short means crowded shorts. Bid-ask spreads narrowing during calm periods then widening sharply on small moves - fragile liquidity from too many similarly-positioned market makers. Order book imbalances showing one-sided positioning. ETF creation/redemption flows skewed in one direction. Hedge fund 13F overlap data showing crowding in specific names. Real-time signals from prime broker reports. The August 2007 quant crisis, January 2018 vol blowup, and various single-stock squeezes all had measurable crowding before the unwind. Watching positioning data is part of risk management for any quantitative or factor-driven strategy.",category:"Behavioral",difficulty:"Advanced"},
{q:"A trader at another desk tells you about a trade their fund is putting on. How do you use that info?",a:"Carefully. The information could be: real and actionable (they want to share genuinely), real but late (they've already put it on, you'd be following), spurious (they're testing your reaction), or trying to get you to take the other side. First, evaluate why they're sharing - what's their incentive? Then assess if the trade aligns with your independent view. If yes, the conviction may be reinforced, but don't size up just because someone else likes it. If no, ask yourself what they see that you don't. Watch for the cascade - multiple desks suddenly mentioning the same trade is a crowding signal. The mental discipline is to make your own decisions; secondhand convictions don't survive drawdowns because the conviction wasn't yours to begin with.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how bid-ask spreads widen during stress and what that signals.",a:"In stress, market makers widen quotes to compensate for higher inventory risk, adverse selection (more informed sellers), and reduced ability to hedge. Spreads on liquid names might go from 1bps to 10-20bps; less liquid names can become essentially untradeable. This signals: reduced market-making capacity, increased volatility expectations, decreased risk appetite from dealers, and potential forced selling that hasn't yet appeared in price. Wider spreads also reduce arbitrage activity, which delays price discovery. The trade signal: when spreads widen across asset classes simultaneously, broader stress is building - derisking is warranted. When spreads start to compress, normalization is underway - adding risk becomes attractive. March 2020 saw spreads on Treasuries widen from 1/64 to 1/4 in days, signaling extreme stress that triggered Fed intervention.",category:"Behavioral",difficulty:"Advanced"},
{q:"If markets are quiet for 3 months, walk me through how that changes your risk-taking.",a:"Counterintuitively, more cautious. Quiet markets seduce traders into oversizing positions - vol is low, daily P&L swings are small, leverage feels safe. But quiet markets also breed positioning concentration and complacency. The setup for vol spikes is exactly the period of preceding calm. Defensive posture: maintain tail hedges even when they look expensive on a carry basis, avoid over-leveraging in correlated positions, keep dry powder for opportunistic deployment when vol returns, watch positioning data for crowding signals. The 2017 lowest VIX in history calm preceded the 2018 volmageddon. The 2019 quiet preceded the COVID shock. Calm markets reward the strategist who can resist the temptation to take more risk just because it feels easy.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through tail risk hedging - how do you size it and when do you take it off?",a:"Tail hedges are insurance - small cost for large payoff in extreme scenarios. Sizing should be a fraction of portfolio (typically 1-3% of NAV) given the negative carry. Common instruments: deep OTM puts on SPX, long VIX futures, gold, JPY longs. The carry drag is real - most months you bleed, occasionally you collect. Take them off when: structural conditions change to reduce tail risk (central bank backstops, fiscal support); valuations no longer warrant the hedge (markets have corrected and tail risk is now priced in); the carry drag is too high to maintain. Don't take them off because they haven't paid yet - that's like canceling fire insurance because there hasn't been a fire. The discipline is that tail hedges aren't supposed to make money frequently; they're supposed to make a lot of money rarely.",category:"Behavioral",difficulty:"Advanced"},
{q:"If your model says one thing but the market is doing another, what's your default behavior?",a:"Investigate the divergence before trading on it. The market is often right because it has information you don't (flows, positioning, news you haven't seen). The model is often right because it filters out noise and reflects fundamental relationships. The honest question: which is wrong, and why? If the model has a known limitation in the current regime (rates breaking historical patterns, factor model in a regime shift), trust the market more. If the market is reacting to noise (short-term flow, technical levels), trust the model. The default behavior should be to reduce position size when model and market diverge, not to double down. Many model-driven blowups happen when traders insist the model is right and the market is wrong for too long.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how you'd handle a losing streak that's affecting your judgment.",a:"Step back from sizing. Reduce position size to 30-50% of normal until the streak breaks - this preserves capital and prevents emotional overcorrection. Avoid taking new high-conviction trades when judgment is compromised; stick to consistent, repeatable setups. Speak to mentors or peers about your process - sometimes a second pair of eyes catches what's wrong. Review the streak honestly: are losses from process failure (bad picks), bad luck (process was sound, market moved against), or regime shift (your strategy doesn't work in current conditions)? Process failures need fixing; bad luck requires patience; regime shifts require strategy adaptation. Don't try to make it all back in one trade - that's where careers end. The psychological discipline is more important than the technical one during streaks.",category:"Behavioral",difficulty:"Advanced"},
{q:"A short-term loss becomes a long-term hold (averaging down) - walk me through when this is reasonable vs. dangerous.",a:"Reasonable: when the original thesis is intact or strengthened by new information, the price decline has improved risk-reward asymmetry, and your sizing accommodates the additional position. Dangerous: when the thesis is broken or weakening, the loss reflects information you didn't have, and the addition is driven by anchoring on entry price rather than forward expected return. The discipline is to evaluate every add as a new trade - would you buy this at current prices given everything you know now? If yes, add. If no, cut. The I'm too far in to sell mentality is the entry point for catastrophic losses. Position size matters too: if the original position was 5% of NAV and adding makes it 10%, you've doubled portfolio concentration based on a worse outcome than expected. That's not risk management.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how you'd evaluate whether a strategy has decayed or just had a bad year.",a:"Look at the underlying drivers, not just the returns. If the strategy depends on factor X being persistent, has factor X been worth less for a structural reason or just temporarily? Are the historical conditions that made the strategy work still present (low rates for carry trades, high correlation for risk premium harvesting)? Check the dispersion of similar strategies - if all similar funds had a bad year, it's likely a regime issue; if most did well and yours didn't, it's idiosyncratic. Look at the rolling Sharpe ratio over multiple windows - 1-year, 3-year, 5-year. Sustained underperformance versus the strategy's historical Sharpe is a real signal. The honest assessment: most strategies have a shelf life. The discipline is recognizing decay and adapting, not stubbornly running a dead strategy because it used to work.",category:"Behavioral",difficulty:"Advanced"},
{q:"If your desk has a large risk imbalance going into a Fed meeting, walk me through how you'd adjust.",a:"Decide if the imbalance reflects your view (you want the risk into the event) or is a residue of position drift (need to neutralize). If by design: confirm sizing is appropriate for the gamma of the event - 25bp surprises move markets, 50bp surprises move them more. If accidental: trim the exposure to neutral or modest position. Liquidity considerations matter - closer to the meeting, liquidity dries up, and exits are more expensive. Use options to monetize asymmetric views: instead of outright short rates, buy puts on TLT or short Eurodollar futures with defined risk. Pre-event positioning should reflect your conviction in the surprise, not just the consensus. Post-event reaction also matters - sometimes the immediate move reverses within hours, so being patient about adding to winning positions is important.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how to size around uncertainty when you don't have full information.",a:"Size smaller than you would with full information. Position size should be inversely proportional to your confidence in the underlying assumptions. If you have a thesis but can't verify a key assumption (regulatory outcome, earnings expectation, macro data), build in a margin of safety - half-size or quarter-size of the conviction position. As new information arrives that confirms the thesis, scale up. As contradictory information arrives, scale down. The discipline is to act on what you know, not assume what you don't. The reverse mistake - sizing as if you knew everything when you didn't - is how traders blow up. The best traders consistently size for the realistic distribution of outcomes rather than the bull case.",category:"Behavioral",difficulty:"Advanced"},
{q:"A retail flow phenomenon (meme stocks, 0DTE) is distorting your view of the market. How do you adapt?",a:"Recognize that retail flow is a real force, not just noise. Meme stocks (GME, AMC) and 0DTE options (40%+ of SPX volume) have changed market microstructure. Adapt by: monitoring retail positioning indicators (Robinhood holdings, options call/put ratios, social media sentiment), avoiding shorts on retail-heavy names with high borrow rates, accepting that momentum can extend beyond fundamental anchors longer than before, hedging gamma exposure around major options expirations more aggressively, watching for unwinds when retail interest fades. The discipline is to update your model of how markets work rather than insisting on the old normal returning. Retail flow has been growing structurally - adapting is required, not optional. The trade lesson: stay structurally net long beta in markets where retail flow is supportive, take profits when retail interest peaks.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how trading psychology differs in a vol-buying environment vs. vol-selling.",a:"Vol-buying environments (long vol strategies, tail hedges): you're underwater more often, bleeding theta, waiting for the payoff. Psychological challenge is patience - staying in the trade through extended quiet periods without rationalizing exit. Many vol buyers quit right before the spike pays. Vol-selling environments (covered calls, short vol strategies): you're making small profits consistently, building false confidence in low-vol regimes. Psychological challenge is discipline - not oversizing positions because the strategy has worked, and being ready to cut when vol regime shifts. Many vol sellers blow up because they didn't size for the inevitable tail event. The difference: vol-buyers fight boredom, vol-sellers fight greed. Both require pre-commitment to sizing rules, but the failure modes are opposite. Long vol fails through impatience; short vol fails through complacency.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how you'd pitch a curve flattener trade to a real money client vs. a hedge fund.",a:"Real money: focus on the macro thesis (Fed hiking cycle, expected growth slowing, demand for duration), keep the structure simple (cash bonds, possibly futures), emphasize benchmark and tracking error implications, mention typical timeline of 3-6 months for the trade to play out. Real money cares about IPS constraints, mandate fit, and total return profile. Hedge fund: emphasize the asymmetric payoff, leverage and capital efficiency (futures vs. cash), specific entry and exit triggers, gamma to expected Fed decisions, and how it fits with their broader macro book. HF wants edge and asymmetric returns; real money wants reasonable risk-adjusted returns within their mandate. Adjust the language: real money speaks about positioning; HFs speak about trades. Both care about market timing but in different ways.",category:"Behavioral",difficulty:"Advanced"},
{q:"A long-only client is convinced the Fed is going to cut. They want to extend duration. What do you say?",a:"First, validate their view with my own framework - do I agree the Fed is cutting on their timeline? If yes, I'd help them understand the curve dynamics: extending in the front-end captures more of the cut benefit, while extending in the 30y is more exposed to inflation re-acceleration or term premium. The trade construction matters - buying 10y on-the-run might not be the best expression versus buying 5y at the steeper part of the curve. Discuss risk: what if the Fed doesn't cut, what's the breakeven move that hurts them, what's the carry. If I disagree with their thesis, I'd present the alternative case with evidence - let them decide. A good salesperson helps clients position for what they believe, not what the salesperson believes.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how to deliver a non-consensus view without sounding overconfident.",a:"Anchor in the data and the reasoning, not the conclusion. Here's what the market is pricing, here's what I think is being missed, here's why - frame it as analysis, not prophecy. Acknowledge the consensus view fairly before presenting yours; clients respect intellectual honesty. Reference specific catalysts or data points that would change your mind - this signals you've thought through the bear case. Avoid absolute language (it has to happen, guaranteed) - use probabilistic framing (60/40 likely, asymmetric risk-reward). Show concrete trade expressions, not just opinions - opinions without trades aren't actionable. The credibility comes from being right consistently over time, but presenting humbly even when you're confident builds the relationship that survives wrong calls.",category:"Behavioral",difficulty:"Advanced"},
{q:"If a client pushes back on your trade idea, walk me through how to respond.",a:"Take the pushback seriously - clients have information you don't (positioning, mandate, view from other counterparties). Listen first before defending. Ask follow-up questions to understand exactly what's bothering them - fundamentals, timing, sizing, structure. Address their concerns with specific evidence, not just restating your original argument. If their pushback identifies a flaw in your thesis, acknowledge it and adjust - that builds long-term credibility. If you still believe the trade, present additional evidence or address their concerns directly. The goal isn't to win the argument; it's to either earn the trade or learn why you shouldn't have brought it. Sometimes the right response is fair point - I'll reconsider this and come back to you rather than fighting in real time.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how you'd identify a client's actual constraints (mandate, benchmark, internal politics).",a:"Ask directly and indirectly. Direct: what's your mandate, what's your benchmark, what's your duration target, what's your risk limit. Indirect: what trades have you done recently and why, what trades have you wanted to do but couldn't, what would your PM say about this idea. Look at their fund's prospectus and 13F filings if institutional. Internal politics: who else needs to sign off, what's their relationship with risk and compliance, what trades have been controversial historically. Listen for hints - I really like this but my PM won't tells you about hierarchy. Building this map of constraints takes months but separates good salespeople from order-takers. The reward is being able to bring trades that fit, increasing hit rate and client trust.",category:"Behavioral",difficulty:"Advanced"},
{q:"A client lost money on a trade you suggested. Walk me through the conversation.",a:"Own it directly. The trade went against us - here's what happened and what I think we should do now. Don't make excuses or blame external factors; clients respect accountability. Reassess the original thesis honestly: was the analysis flawed, was it bad timing, was it bad luck? Be specific. Discuss what you've learned and what you'd do differently. If the thesis is intact and the move was technical, discuss whether to add or hold. If the thesis is broken, discuss exiting and what comes next. The worst response is silence or deflection - that loses the relationship permanently. The best response builds trust because clients know losses happen; what they value is honest engagement during the bad moments. Long-term relationships are built in the losses, not the wins.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how you'd recap a major earnings move for an institutional client.",a:"Lead with the headline: The stock is down 12% on results, here's why. Then break down: what the company reported (specific numbers), what the consensus expected (gap to expectations), what management said on the call (key quotes from CEO/CFO), what's changed for the forward outlook. Identify the 2-3 main drivers of the move - usually one is the catalyst, others are amplifiers. Discuss implications for related names (sector, suppliers, customers) and trades. End with actionable: I'd consider X on this move or I'd avoid Y here. Keep it under 200 words for written; under 60 seconds for verbal. Clients are reading multiple recaps - yours has to be tight and add value beyond the headline. The pattern: facts, then analysis, then trade implications.",category:"Behavioral",difficulty:"Advanced"},
{q:"If three different clients are all positioned in the same trade, walk me through what you tell each of them.",a:"The information itself is non-confidential (positioning is observable from flows), but specific client positions are confidential. I'd communicate the broader market positioning trend to all three: There's significant positioning in this trade - be aware of crowding risk. Each client benefits from knowing this. I would not disclose which specific clients hold the trade. If the crowding represents a risk to one of them, I'd raise it directly: You're in a crowded position; here's how to hedge or reduce. If it's an opportunity (they could be the one to exit first), I'd discuss exit timing without revealing what others might do. The discipline is to add value through market awareness without breaching the trust that lets you see flow in the first place.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how a sales-trader relationship actually works on a desk.",a:"The salesperson sources demand from clients - what they want to buy or sell, in what size, at what price tolerance. The trader manages the desk's book - inventory, hedging, market making. The salesperson translates client need to the trader, who quotes a price (bid for client sell, offer for client buy) with consideration of inventory, market conditions, and risk appetite. The salesperson negotiates with the client on price; the trader adjusts based on flow direction. Information flows both ways: traders share market color the salesperson can use with clients; salespeople give traders flow intelligence that informs positioning. The relationship is tight on good desks - daily collaboration on big trades. The friction is when sales pushes for tighter quotes (to keep client) while trading pushes for wider quotes (to protect book). Resolution: trust and history.",category:"Behavioral",difficulty:"Advanced"},
{q:"A pension fund client wants to hedge $2B of equity exposure. Walk me through what you propose.",a:"First, understand their objective: tactical hedge for a specific period, or strategic hedge for a longer horizon. Then their cost tolerance and view on upside. Options structures: simple put protection (5% OTM SPX puts, 6-month, costs maybe 2-3%); put spreads (buy ATM, sell deep OTM, reduces cost); collar (sell calls to fund puts, caps upside but costless); variance swap (pure vol exposure); futures overlay (sell SPX futures, beta-adjust for any equity portfolio that differs from index). For a pension, considerations include accounting treatment, tracking error to liability discount rate, and operational complexity. I'd present 2-3 structures with cost/protection trade-offs, let them pick. Sizing: $2B of equity might need $200M-2B notional of options depending on protection level. Avoid over-engineering - simple structures win for institutional clients.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how to communicate a complex options structure without losing the client.",a:"Translate to plain English first, jargon second. You're buying the right to sell at $100, paying $5 for it is better than long an ATM 100 put at $5 premium. Use visual aids - payoff diagrams that show their P&L at different stock prices. Walk through scenarios: stock at $90, $100, $110 - what happens in each case. Use analogies: insurance for the put, capping upside as a ceiling for short calls. Avoid Greeks unless the client is sophisticated; even then, explain in terms of P&L impact rather than mathematical definitions. Confirm understanding by having them describe the trade back to you in their own words. The best salespeople are translators - making sophisticated structures accessible without dumbing them down.",category:"Behavioral",difficulty:"Advanced"},
{q:"If consensus is wrong about a Fed move, walk me through how you'd position your clients ahead.",a:"Identify the variance perception first: what data or framework do I see that consensus doesn't. Then quantify the asymmetric payoff: if I'm right, what's the expected return; if I'm wrong, what's the cost. For real money clients, suggest modest positioning adjustments - duration extension or reduction, curve flattener or steepener. For HF clients, suggest higher-conviction expressions - options on Fed funds futures, SOFR call/put spreads. Time the recommendation: too early and clients don't engage; too late and the move is mostly done. Track record matters - clients are more willing to take non-consensus positions from salespeople who have been right before. The sales conversation should be: I see things differently than consensus, here's why, here's how to position. Let them decide whether to engage.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how you'd identify positioning imbalances by talking to clients.",a:"Track aggregate client flows over time - who's been buying, who's been selling, in what size. Pattern recognition: if every long-only is selling duration while every macro fund is buying, there's an imbalance worth noticing. Specific conversations: What's the most crowded trade you see? Where are you against consensus? Listen for repeated themes across clients. Cross-reference with public positioning data (COT reports, ETF flows, prime broker data). Notice when clients stop wanting to discuss certain trades - sometimes silence is the signal that they've gotten out. Build a mental map of positioning by client type and update it weekly. The salesperson with the best positioning intelligence is the one clients call for color, which creates a virtuous loop.",category:"Behavioral",difficulty:"Advanced"},
{q:"A client wants something that doesn't make sense for their portfolio. Walk me through your response.",a:"Pause before executing. Help me understand the rationale - what's driving this? Often clients have constraints or information you don't see. If after listening it still doesn't make sense, push back diplomatically: I want to flag that this looks inconsistent with [their stated objective/mandate/recent positioning]. Want to walk through the logic? Sometimes they reconsider and reduce size or change structure. Sometimes they confirm and you execute - your job is to advise, not refuse. Document the conversation if the trade looks problematic from a suitability standpoint. The discipline: a salesperson who only pushes products has a short shelf life. The salesperson who occasionally talks a client out of a bad idea earns trust that converts to long-term flow.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how to balance educating a client vs. just executing their trade.",a:"Match the response to the client's sophistication and need. A sophisticated PM who knows what they want should be executed with minimal friction - long preambles waste their time. A junior PM or rotational analyst may benefit from context - here's what we're seeing, here's the trade-off. Some clients want education routinely; others want execution and don't appreciate unsolicited views. Read the relationship and the context. Education should always be value-add, not condescending. The ideal is to add insight that improves the trade or relationship without slowing execution. Some salespeople over-educate to demonstrate value, which is counterproductive. The best salespeople know when to be brief and when to elaborate.",category:"Behavioral",difficulty:"Advanced"},
{q:"If you have a sales tearsheet for a structured product, walk me through how to deliver it concisely.",a:"Lead with the value proposition in one sentence: This is a 3-year structured note paying 8% annually, with downside protection to -20%. Then payoff structure: Here's what you get at each level of the underlying. Then key features: maturity, structure type, counterparty, fees. Most clients won't read the full document - verbal delivery should be under 90 seconds. Anticipate two or three follow-up questions and have answers ready (Why this structure? Why now? How does it compare to other options?). The tearsheet itself should be one page max, with the key economics highlighted, payoff diagram visible, and disclaimers on page two for compliance. The discipline is ruthless editing - every word that doesn't move the client closer to a decision should be cut.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how to use market color vs. actionable insight in a morning call.",a:"Market color is the description - rates higher overnight, dollar firmer, equities mixed. Actionable insight is the implication - this argues for fading the rates move and looking for opportunities in EM FX. The best morning calls integrate both. Start with the most important market move, explain the driver, then connect to a specific trade idea or positioning recommendation. Avoid generic commentary that any source could provide - your client has Bloomberg too. The value-add is your interpretation and trade conviction. Keep it under 5 minutes; clients are juggling multiple voices in the morning. End with what to watch for the rest of the day - calendar events, data releases, technicals. The best morning calls are remembered for one insight; the average ones are forgotten by 10am.",category:"Behavioral",difficulty:"Advanced"},
{q:"A client only sees you when they're trading. How do you build value outside of execution?",a:"Become indispensable in non-trading moments. Send relevant research with your own annotations - I think the chart on page 4 is the key point. Share positioning observations that inform their decisions. Host conferences, panels, or expert calls they can attend. Forward IB research, idea pieces, or technical reads that fit their style. Be the first call when a major event happens - a quick voice memo on a Fed surprise builds memory. The discipline is consistent, low-friction touchpoints that add value without asking for execution. Over 12 months, this should compound into the client thinking of you as their resource, not just their executor. Salespeople who only show up to execute are commodity providers; the ones who add intellectual value become trusted advisors.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through cross-selling - when is it value-add and when is it noise?",a:"Value-add: client mentioned they're hedging duration; you mention you have an axe in 5y Treasuries that fits. Client is concerned about FX exposure; you connect them with the FX desk for a forward conversation. Cross-selling that fits a client's actual need is appreciated. Noise: pitching every product to every client regardless of fit; bringing in colleagues to push something the client didn't ask for; using cross-sell calls as ways to expand fees rather than add value. The test: would the client agree this cross-sell was useful even if they don't act on it? If yes, it's value-add. If no, it's noise. The best cross-selling is invisible - the client just notices that this firm seems to anticipate their needs.",category:"Behavioral",difficulty:"Advanced"},
{q:"If you have one minute with a senior PM, walk me through how to deliver a trade idea.",a:"Lead with the conclusion: I think SPX is a tactical short here. Then the variant: Consensus sees rates falling; I think they overshoot up before they fall. Then the trade: Buy 1-month SPX puts 3% OTM, financed by selling 6-month 5% OTM, costs 20bps. Then the risk: I'm wrong if rates fall faster than expected. Stop. Don't try to walk through the whole thesis - the senior PM will ask questions if interested. Brevity is the discipline. The senior PM is evaluating the idea quality and your ability to communicate it concisely. Long-winded pitches signal that you don't have a clear view. Anticipate the two or three questions they'll ask and have crisp answers. If they're interested, the conversation extends; if not, you've respected their time. Both outcomes are wins.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through what differentiates a great salesperson from a mediocre one.",a:"Hit rate of trade ideas - great salespeople have ideas that work more often. Depth of client knowledge - they understand each client's constraints and preferences, not just what they trade. Ability to bring multi-asset views - connecting rates, FX, equities, commodities for clients who care about the macro picture. Trust during losses - owning bad recommendations rather than deflecting. Network across the firm - knowing who to call for what without forcing the client to chase. Market intuition - recognizing flow patterns before they show up in price. Communication - being concise without losing nuance. The mediocre salesperson is a quote provider; the great one is a trusted advisor who happens to also provide quotes. The compensation gap reflects this gap in value-add.",category:"Behavioral",difficulty:"Advanced"},
{q:"A client asks what are smart accounts doing? How do you respond without breaching confidentiality?",a:"Speak in aggregate, not specifics. I'm seeing real money buying duration but hedge funds are short the long end. That's market color that anyone with similar flow visibility would have. Never name specific clients or specific positions. If pushed for more detail, redirect: I can share market color but obviously can't name specific clients. The client should respect this - they wouldn't want their positions discussed with others either. Building this trust is what allows you to see flow in the first place. The salesperson who casually shares specifics loses the trust that lets them serve any client. The salesperson who guards confidentiality even at the cost of seeming less informed builds long-term flow.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how you'd handle a client who consistently puts on losing trades you recommended against.",a:"Document the pattern - note your warnings before the trades and the outcomes. Over time, this builds your credibility because you can reference specific instances (like the rates trade we discussed in March). Don't say I told you so - that destroys relationships. Continue to provide your honest views; the client may eventually realize and adjust. Keep the conversation focused on forward decisions, not past mistakes. If the pattern persists and risks the relationship, consider escalating internally - sometimes a different salesperson is a better fit for that client's style. The discipline: provide value through honest advice even when it doesn't earn flow short-term. Clients eventually appreciate the salesperson who told them no when they should have.",category:"Behavioral",difficulty:"Advanced"},
{q:"If you're covering a CIO who travels constantly, walk me through how you stay relevant.",a:"Async communication: short voice memos, concise emails with one-sentence value propositions. Time-zone awareness: send updates when they'll be in transit between meetings, not at 3am their local time. Curate ruthlessly - only escalate things they need to act on or know. Build relationships with their team - analysts, ops, deputy CIO - who can be reached when the CIO can't. Use scheduled touch points (quarterly reviews, conference panels) for the substantive discussions; daily flow for execution. Notice when they're back in town and offer to come by their office for 15 minutes. The discipline: respect their time and constraints, add value with brevity, build relationships beyond just them. The CIO will remember the salesperson who made their life easier, not the one who flooded their inbox.",category:"Behavioral",difficulty:"Advanced"},
{q:"Walk me through how to balance relationship management with market judgment when they conflict.",a:"Relationship management is about the long-term franchise; market judgment is about the next trade being right. They conflict when a client wants something you think is a bad idea. The resolution: short-term, the relationship usually wins - execute the trade with appropriate caveats. Long-term, your market judgment is what builds the relationship - clients value salespeople who told them no when they should have. The balance is being firm with your views without being preachy, being respectful of their autonomy, and being willing to lose individual trades to build longer-term trust. The worst behavior is either of two extremes - never pushing back (you become a yes-person, valued for execution only) or constantly arguing (you become exhausting, eventually fired). The middle path: provide honest views, accept their decisions, document for future reference, and build the relationship that survives the bad trades they put on against your advice.",category:"Behavioral",difficulty:"Advanced"},
];
